HYPOTHESIS_000003_AUTOGLUON_002_PY_1DE6FF1BE7_SOURCE = 'import numpy as np\nimport pandas as pd\n\ndef add_galactic_sightline_context(raw, deps, aux):\n    alpha_rad = np.deg2rad((pd.to_numeric(raw["alpha"], errors="coerce") % 360.0).to_numpy(dtype=float))\n    delta_rad = np.deg2rad(pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=float))\n\n    # Equatorial unit-sphere coordinates (wrap-safe via alpha modulo 360)\n    cos_delta = np.cos(delta_rad)\n    x_eq = cos_delta * np.cos(alpha_rad)\n    y_eq = cos_delta * np.sin(alpha_rad)\n    z_eq = np.sin(delta_rad)\n\n    # J2000 equatorial -> Galactic rotation matrix\n    x_gal = (\n        -0.0548755604 * x_eq\n        + -0.8734370902 * y_eq\n        + -0.4838350155 * z_eq\n    )\n    y_gal = (\n        0.4941094279 * x_eq\n        + -0.4448296300 * y_eq\n        + 0.7469822445 * z_eq\n    )\n    z_gal = (\n        -0.8676661490 * x_eq\n        + -0.1980763734 * y_eq\n        + 0.4559837762 * z_eq\n    )\n\n    z_clip = np.clip(z_gal, -1.0, 1.0)\n    b_rad = np.arcsin(z_clip)\n    b_deg = np.degrees(b_rad)\n    abs_b_deg = np.abs(b_deg)\n\n    l_rad = np.arctan2(y_gal, x_gal)\n    l_deg = np.degrees(l_rad) % 360.0\n    l_rad = np.deg2rad(l_deg)\n\n    sin_l = np.sin(l_rad)\n    cos_l = np.cos(l_rad)\n    sin_b = np.sin(b_rad)\n    cos_b = np.cos(b_rad)\n\n    dist_to_galactic_center = np.degrees(np.arccos(np.clip(x_gal, -1.0, 1.0)))\n    dist_to_galactic_anticenter = np.degrees(np.arccos(np.clip(-x_gal, -1.0, 1.0)))\n    dist_to_north_galactic_pole = np.degrees(np.arccos(np.clip(z_gal, -1.0, 1.0)))\n    dist_to_south_galactic_pole = np.degrees(np.arccos(np.clip(-z_gal, -1.0, 1.0)))\n\n    b_band_edges = (0.0, 10.0, 20.0, 35.0, 50.0, 70.0, 90.0000001)\n    b_band_labels = ("0-10", "10-20", "20-35", "35-50", "50-70", "70-90")\n    b_band = pd.cut(\n        abs_b_deg,\n        bins=b_band_edges,\n        labels=b_band_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    l_sector_edges = tuple(np.arange(0.0, 390.0, 30.0))\n    l_sector_labels = tuple(f"{int(start):03d}-{int(start + 30):03d}" for start in l_sector_edges[:-1])\n    l_sector = pd.cut(\n        l_deg,\n        bins=l_sector_edges,\n        labels=l_sector_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    b_band_str = b_band.astype(str)\n    l_sector_str = l_sector.astype(str)\n    crossed_regime = b_band_str + "|" + l_sector_str\n\n    return pd.DataFrame(\n        {\n            "eq_x": x_eq,\n            "eq_y": y_eq,\n            "eq_z": z_eq,\n            "gal_l_deg": l_deg,\n            "gal_b_deg": b_deg,\n            "gal_abs_b_deg": abs_b_deg,\n            "gal_sin_l": sin_l,\n            "gal_cos_l": cos_l,\n            "gal_sin_b": sin_b,\n            "gal_cos_b": cos_b,\n            "gal_plane_angular_distance_deg": abs_b_deg,\n            "gal_dist_to_galactic_center_deg": dist_to_galactic_center,\n            "gal_dist_to_galactic_anticenter_deg": dist_to_galactic_anticenter,\n            "gal_dist_to_north_pole_deg": dist_to_north_galactic_pole,\n            "gal_dist_to_south_pole_deg": dist_to_south_galactic_pole,\n            "gal_b_band": b_band_str,\n            "gal_l_sector": l_sector_str,\n            "gal_b_band_l_sector": crossed_regime,\n        },\n        index=raw.index,\n    )\n\nFEATURE_GROUPS = [\n    {\n        "name": "galactic_sightline_context",\n        "fn": add_galactic_sightline_context,\n        "depends_on": [],\n        "description": "Create Galactic coordinate-derived spatial features including smooth angular encodings, center/pole distances, and coarse latitude-longitude regime bins.",\n    }\n]'

HYPOTHESIS_000017_AUTOGLUON_001_PY_F265354A39_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_COSMO_H0 = 70.0\n_COSMO_OMEGA_M = 0.3\n_COSMO_OMEGA_L = 0.7\n_COSMO_C_KM_S = 299792.458\n_COSMO_Z_MIN = 1e-4\n_COSMO_GRID_POINTS = 2048\n_COSMO_DL_MIN_MPC = 1.0e-4\n_COSMO_DL_MAX_MPC = 1.0e7\n_COSMO_ABS_MAG_MIN = -90.0\n_COSMO_ABS_MAG_MAX = 80.0\n_BANDS = ("u", "g", "r", "i", "z")\n_THRESHOLDS_M = (-10.0, -18.0, -23.0, -27.0)\n\n\ndef _luminosity_distance_mpc(redshift_for_distance):\n    redshift_for_distance = np.asarray(redshift_for_distance, dtype=np.float64)\n    if redshift_for_distance.size == 0:\n        return redshift_for_distance.copy()\n\n    z_max = float(np.max(redshift_for_distance))\n    if not np.isfinite(z_max):\n        z_max = float(_COSMO_Z_MIN)\n\n    # Build a fixed one-dimensional cosmology integral grid and re-use it for all rows.\n    z_grid = np.linspace(0.0, z_max, num=_COSMO_GRID_POINTS)\n    hz = np.sqrt(_COSMO_OMEGA_M * np.power(1.0 + z_grid, 3.0) + _COSMO_OMEGA_L)\n    inv_hz = 1.0 / hz\n\n    if _COSMO_GRID_POINTS > 1:\n        dz = z_grid[1] - z_grid[0]\n        seg = (inv_hz[:-1] + inv_hz[1:]) * 0.5 * dz\n        comoving = np.empty_like(z_grid)\n        comoving[0] = 0.0\n        np.cumsum(seg, out=comoving[1:])\n    else:\n        comoving = np.zeros_like(z_grid)\n\n    # Mpc = (c/H0) * (integral 0..z dz/E(z)); DL = (1+z) * D_C\n    dl = (1.0 + redshift_for_distance) * np.interp(redshift_for_distance, z_grid, comoving * (_COSMO_C_KM_S / _COSMO_H0))\n    dl = np.clip(dl, _COSMO_DL_MIN_MPC, _COSMO_DL_MAX_MPC)\n    return dl\n\n\ndef add_redshift_luminosity_plausibility(raw, deps, aux):\n    del deps, aux  # explicit dependency/aux declaration-only no-op\n    z = raw["redshift"].to_numpy(dtype=np.float64, copy=False)\n    z_eff = np.maximum(z, _COSMO_Z_MIN)\n\n    dist_mpc = _luminosity_distance_mpc(z_eff)\n    dist_mpc = np.clip(dist_mpc, _COSMO_DL_MIN_MPC, _COSMO_DL_MAX_MPC)\n    log10_dl = np.log10(dist_mpc)\n\n    abs_mag = {}\n    for band in _BANDS:\n        m_obs = raw[band].to_numpy(dtype=np.float64, copy=False)\n        m_abs = m_obs - 5.0 * log10_dl - 25.0\n        abs_mag[band] = np.clip(m_abs, _COSMO_ABS_MAG_MIN, _COSMO_ABS_MAG_MAX)\n\n    abs_matrix = np.column_stack((abs_mag["u"], abs_mag["g"], abs_mag["r"], abs_mag["i"], abs_mag["z"]))\n    abs_center_ri = 0.5 * (abs_mag["r"] + abs_mag["i"])\n    abs_brightest = np.min(abs_matrix, axis=1)\n    abs_faintest = np.max(abs_matrix, axis=1)\n    abs_spread = abs_faintest - abs_brightest\n    abs_mean = np.mean(abs_matrix, axis=1)\n\n    thresh_stellar, thresh_galaxy, thresh_qso, thresh_extreme = _THRESHOLDS_M\n\n    features = {\n        "redshift_non_positive": z <= 0.0,\n        "redshift_very_low": z < 0.01,\n        "redshift_for_distance": z_eff,\n        "luminosity_distance_mpc": dist_mpc,\n        "abs_mag_u": abs_mag["u"],\n        "abs_mag_g": abs_mag["g"],\n        "abs_mag_r": abs_mag["r"],\n        "abs_mag_i": abs_mag["i"],\n        "abs_mag_z": abs_mag["z"],\n        "abs_mag_ri_center": abs_center_ri,\n        "abs_mag_brightest_band": abs_brightest,\n        "abs_mag_faintest_band": abs_faintest,\n        "abs_mag_band_spread": abs_spread,\n        "abs_mag_band_mean": abs_mean,\n        "abs_mag_margin_to_stellar_scale": abs_center_ri - thresh_stellar,\n        "abs_mag_margin_to_galaxy_scale": abs_center_ri - thresh_galaxy,\n        "abs_mag_margin_to_quasar_scale": abs_center_ri - thresh_qso,\n        "abs_mag_margin_to_extreme_quasar_scale": abs_center_ri - thresh_extreme,\n        "abs_mag_r_margin_to_stellar_scale": abs_mag["r"] - thresh_stellar,\n        "abs_mag_r_margin_to_galaxy_scale": abs_mag["r"] - thresh_galaxy,\n        "abs_mag_r_margin_to_quasar_scale": abs_mag["r"] - thresh_qso,\n        "abs_mag_r_margin_to_extreme_quasar_scale": abs_mag["r"] - thresh_extreme,\n        "abs_band_spread_uirz": (abs_mag["u"] - abs_mag["r"]) + (abs_mag["r"] - abs_mag["i"]) + (abs_mag["i"] - abs_mag["z"]),\n    }\n\n    return pd.DataFrame(features, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshift_luminosity_plausibility",\n        "fn": add_redshift_luminosity_plausibility,\n        "depends_on": [],\n        "description": "Convert apparent ugri z magnitudes into redshift-scaled pseudo absolute magnitudes with robust distance-distance proxies and regime-distance summaries.",\n    }\n]'

HYPOTHESIS_000018_AUTOGLUON_002_PY_10991284F9_SOURCE = 'import numpy as np\nimport pandas as pd\n\nSPECTRAL_TYPE_TO_EXPECTATION = {\n    "O/B": 0.00,\n    "A/F": 0.33,\n    "G/K": 0.67,\n    "M": 1.00,\n}\nGALAXY_POPULATION_TO_EXPECTATION = {\n    "Blue_Cloud": 0.00,\n    "Red_Sequence": 1.00,\n}\nCOLOR_WEIGHT_TUPLE = (0.40, 0.30, 0.20, 0.10)\n\n\ndef _sanitize_score(series, fill_value=0.5):\n    return series.where(np.isfinite(series), fill_value).astype("float64")\n\n\ndef _robust_scale_color(values, q02, q98):\n    span = q98 - q02\n    if not np.isfinite(span) or span == 0:\n        scaled = pd.Series(0.5, index=values.index, dtype="float64")\n        invalid = pd.Series(True, index=values.index, dtype="bool")\n        return scaled, invalid\n\n    raw_scaled = (values - q02) / span\n    invalid = ~np.isfinite(raw_scaled)\n    scaled = raw_scaled.clip(lower=0.0, upper=1.0)\n    scaled = scaled.where(~invalid, 0.5)\n    return scaled, invalid\n\n\ndef _residual_summary(d1, d2, d3, d4):\n    residuals = pd.concat([d1, d2, d3, d4], axis=1)\n    residuals = residuals.where(np.isfinite(residuals), 0.5)\n    mean = residuals.mean(axis=1)\n    median = residuals.median(axis=1)\n    l1 = residuals.abs().sum(axis=1)\n    l2 = (residuals ** 2).sum(axis=1)\n    max_abs = residuals.abs().max(axis=1)\n    return mean, median, l1, l2, max_abs\n\n\ndef add_catalog_tag_color_concordance(raw, deps, aux):\n    u = pd.to_numeric(raw["u"], errors="coerce")\n    g = pd.to_numeric(raw["g"], errors="coerce")\n    r = pd.to_numeric(raw["r"], errors="coerce")\n    i = pd.to_numeric(raw["i"], errors="coerce")\n    z = pd.to_numeric(raw["z"], errors="coerce")\n    redshift = pd.to_numeric(raw["redshift"], errors="coerce")\n\n    c1 = u - g\n    c2 = g - r\n    c3 = r - i\n    c4 = i - z\n\n    q1_lo = c1.quantile(0.02)\n    q1_hi = c1.quantile(0.98)\n    q2_lo = c2.quantile(0.02)\n    q2_hi = c2.quantile(0.98)\n    q3_lo = c3.quantile(0.02)\n    q3_hi = c3.quantile(0.98)\n    q4_lo = c4.quantile(0.02)\n    q4_hi = c4.quantile(0.98)\n\n    r1, r1_invalid = _robust_scale_color(c1, q1_lo, q1_hi)\n    r2, r2_invalid = _robust_scale_color(c2, q2_lo, q2_hi)\n    r3, r3_invalid = _robust_scale_color(c3, q3_lo, q3_hi)\n    r4, r4_invalid = _robust_scale_color(c4, q4_lo, q4_hi)\n\n    spectral_type_exp = raw["spectral_type"].map(SPECTRAL_TYPE_TO_EXPECTATION)\n    galaxy_pop_exp = raw["galaxy_population"].map(GALAXY_POPULATION_TO_EXPECTATION)\n\n    te = pd.to_numeric(spectral_type_exp, errors="coerce").fillna(0.5)\n    ge = pd.to_numeric(galaxy_pop_exp, errors="coerce").fillna(0.5)\n\n    R_raw = (\n        COLOR_WEIGHT_TUPLE[0] * r1\n        + COLOR_WEIGHT_TUPLE[1] * r2\n        + COLOR_WEIGHT_TUPLE[2] * r3\n        + COLOR_WEIGHT_TUPLE[3] * r4\n    )\n    R = _sanitize_score(R_raw)\n\n    mismatch_tag_raw = (R - te).abs()\n    mismatch_pop_raw = (R - ge).abs()\n\n    tag_mismatch = _sanitize_score(mismatch_tag_raw)\n    pop_mismatch = _sanitize_score(mismatch_pop_raw)\n\n    tag_agreement = _sanitize_score(1.0 - mismatch_tag_raw)\n    pop_agreement = _sanitize_score(1.0 - mismatch_pop_raw)\n\n    tag_gap = _sanitize_score(te - ge)\n    tag_gap_abs = _sanitize_score((te - ge).abs())\n\n    tag_resid_c1 = _sanitize_score((r1 - te).where(~r1_invalid, 0.5))\n    tag_resid_c2 = _sanitize_score((r2 - te).where(~r2_invalid, 0.5))\n    tag_resid_c3 = _sanitize_score((r3 - te).where(~r3_invalid, 0.5))\n    tag_resid_c4 = _sanitize_score((r4 - te).where(~r4_invalid, 0.5))\n\n    pop_resid_c1 = _sanitize_score((r1 - ge).where(~r1_invalid, 0.5))\n    pop_resid_c2 = _sanitize_score((r2 - ge).where(~r2_invalid, 0.5))\n    pop_resid_c3 = _sanitize_score((r3 - ge).where(~r3_invalid, 0.5))\n    pop_resid_c4 = _sanitize_score((r4 - ge).where(~r4_invalid, 0.5))\n\n    tag_resid_mean, tag_resid_median, tag_resid_l1, tag_resid_l2, tag_resid_maxabs = _residual_summary(\n        tag_resid_c1, tag_resid_c2, tag_resid_c3, tag_resid_c4\n    )\n    pop_resid_mean, pop_resid_median, pop_resid_l1, pop_resid_l2, pop_resid_maxabs = _residual_summary(\n        pop_resid_c1, pop_resid_c2, pop_resid_c3, pop_resid_c4\n    )\n\n    w_z = 1.0 - ((redshift - 0.45) / 1.25).clip(lower=0.0, upper=1.0)\n    w_z = w_z.where(np.isfinite(w_z), 0.0).clip(lower=0.0, upper=1.0)\n\n    invalid_indicator = (\n        ~np.isfinite(R_raw)\n        | ~np.isfinite(mismatch_tag_raw)\n        | ~np.isfinite(mismatch_pop_raw)\n        | ~np.isfinite(tag_resid_c1)\n        | ~np.isfinite(tag_resid_c2)\n        | ~np.isfinite(tag_resid_c3)\n        | ~np.isfinite(tag_resid_c4)\n        | ~np.isfinite(pop_resid_c1)\n        | ~np.isfinite(pop_resid_c2)\n        | ~np.isfinite(pop_resid_c3)\n        | ~np.isfinite(pop_resid_c4)\n        | r1_invalid\n        | r2_invalid\n        | r3_invalid\n        | r4_invalid\n    )\n    valid_indicator = (~invalid_indicator).astype("bool")\n\n    htc = ((te <= 0.34) & (R >= 0.67) & valid_indicator).astype("int8")\n    ctc = ((te >= 0.67) & (R <= 0.33) & valid_indicator).astype("int8")\n    rbc = ((ge >= 0.67) & (R <= 0.33) & valid_indicator).astype("int8")\n    brc = ((ge <= 0.34) & (R >= 0.67) & valid_indicator).astype("int8")\n    dual_contra = ((tag_mismatch >= 0.35) & (pop_mismatch >= 0.35) & valid_indicator).astype("int8")\n\n    features = pd.DataFrame(index=raw.index)\n    features["c1_u_minus_g"] = c1\n    features["c2_g_minus_r"] = c2\n    features["c3_r_minus_i"] = c3\n    features["c4_i_minus_z"] = c4\n\n    features["r1_u_minus_g"] = r1\n    features["r2_g_minus_r"] = r2\n    features["r3_r_minus_i"] = r3\n    features["r4_i_minus_z"] = r4\n\n    features["redness_R"] = R\n    features["te"] = te\n    features["ge"] = ge\n    features["te_ge_signed_gap"] = tag_gap\n    features["te_ge_abs_gap"] = tag_gap_abs\n    features["te_minus_ge_signed"] = te - ge\n    features["te_minus_ge_abs"] = (te - ge).abs()\n\n    features["tag_agreement"] = tag_agreement\n    features["pop_agreement"] = pop_agreement\n    features["tag_mismatch"] = tag_mismatch\n    features["pop_mismatch"] = pop_mismatch\n\n    features["tag_resid_c1"] = tag_resid_c1\n    features["tag_resid_c2"] = tag_resid_c2\n    features["tag_resid_c3"] = tag_resid_c3\n    features["tag_resid_c4"] = tag_resid_c4\n\n    features["pop_resid_c1"] = pop_resid_c1\n    features["pop_resid_c2"] = pop_resid_c2\n    features["pop_resid_c3"] = pop_resid_c3\n    features["pop_resid_c4"] = pop_resid_c4\n\n    features["tag_resid_mean"] = tag_resid_mean\n    features["tag_resid_median"] = tag_resid_median\n    features["tag_resid_l1"] = tag_resid_l1\n    features["tag_resid_l2"] = tag_resid_l2\n    features["tag_resid_maxabs"] = tag_resid_maxabs\n\n    features["pop_resid_mean"] = pop_resid_mean\n    features["pop_resid_median"] = pop_resid_median\n    features["pop_resid_l1"] = pop_resid_l1\n    features["pop_resid_l2"] = pop_resid_l2\n    features["pop_resid_maxabs"] = pop_resid_maxabs\n\n    features["redshift_trust_gate"] = w_z\n\n    features["htc"] = htc\n    features["ctc"] = ctc\n    features["rbc"] = rbc\n    features["brc"] = brc\n    features["dual_contra"] = dual_contra\n\n    features["tag_agreement_wz"] = tag_agreement * w_z\n    features["pop_agreement_wz"] = pop_agreement * w_z\n    features["tag_mismatch_wz"] = tag_mismatch * w_z\n    features["pop_mismatch_wz"] = pop_mismatch * w_z\n    features["tag_gap_abs_wz"] = tag_gap_abs * w_z\n    features["te_ge_abs_gap_wz"] = (tag_gap_abs) * w_z\n\n    features["tag_resid_mean_wz"] = tag_resid_mean * w_z\n    features["tag_resid_median_wz"] = tag_resid_median * w_z\n    features["tag_resid_l1_wz"] = tag_resid_l1 * w_z\n    features["tag_resid_l2_wz"] = tag_resid_l2 * w_z\n    features["tag_resid_maxabs_wz"] = tag_resid_maxabs * w_z\n\n    features["pop_resid_mean_wz"] = pop_resid_mean * w_z\n    features["pop_resid_median_wz"] = pop_resid_median * w_z\n    features["pop_resid_l1_wz"] = pop_resid_l1 * w_z\n    features["pop_resid_l2_wz"] = pop_resid_l2 * w_z\n    features["pop_resid_maxabs_wz"] = pop_resid_maxabs * w_z\n\n    features["htc_wz"] = htc.astype("float64") * w_z\n    features["ctc_wz"] = ctc.astype("float64") * w_z\n    features["rbc_wz"] = rbc.astype("float64") * w_z\n    features["brc_wz"] = brc.astype("float64") * w_z\n    features["dual_contra_wz"] = dual_contra.astype("float64") * w_z\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "catalog_tag_color_concordance",\n        "fn": add_catalog_tag_color_concordance,\n        "depends_on": [],\n        "description": "Build redshift-gated tag and population color-consistency features from robustly quantile-scaled ugriz color indices.",\n    }\n]'

HYPOTHESIS_000021_AUTOGLUON_003_PY_6859B56132_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_EPS = 1e-6\n_LM_SCALE = -0.9210340371976183\n_BANDS = ("u", "g", "r", "i", "z")\n_COLOR_PAIRS = (("u", "g"), ("g", "r"), ("r", "i"), ("i", "z"), ("u", "r"), ("u", "i"), ("u", "z"), ("g", "z"), ("r", "z"))\n_ZR_MAX = 1_000_000.0\n\n\ndef _to_float(series):\n    return pd.to_numeric(series, errors="coerce").astype("float64")\n\n\ndef _finite(series):\n    return series.replace([np.inf, -np.inf], np.nan).fillna(0.0)\n\n\ndef _dependency_columns(deps):\n    cols = set()\n    if deps:\n        for dep_df in deps.values():\n            if isinstance(dep_df, pd.DataFrame):\n                cols.update(dep_df.columns)\n    return cols\n\n\ndef add_aide_broadband_flux_ratios(raw, deps, aux):\n    idx = raw.index\n    existing = _dependency_columns(deps)\n    features = {}\n    lf = {}\n\n    # Bandwise magnitude -> linearized magnitude and pseudo-flux features.\n    for band in _BANDS:\n        m = _to_float(raw[band])\n        lm = (_LM_SCALE * m).clip(lower=-20.0, upper=10.0)\n        lf_band = np.exp(lm)\n        features[f"lm_{band}"] = _finite(lm)\n        features[f"lf_{band}"] = _finite(lf_band)\n        lf[band] = _finite(lf_band)\n\n    # Pairwise first-order color geometry features.\n    for band_a, band_b in _COLOR_PAIRS:\n        a = _to_float(raw[band_a])\n        b = _to_float(raw[band_b])\n\n        color_gap = (a - b).abs()\n        denom = b.abs().clip(lower=_EPS)\n        ratio_norm = (a - b) / denom\n        safe_mag_ratio = a / denom\n\n        gap_name = f"color_gap_{band_a}_{band_b}"\n        ratio_name = f"ratio_norm_{band_a}_{band_b}"\n        safe_name = f"safe_mag_ratio_{band_a}_{band_b}"\n\n        if gap_name not in existing:\n            features[gap_name] = _finite(color_gap)\n        if ratio_name not in existing:\n            features[ratio_name] = _finite(ratio_norm)\n        if safe_name not in existing:\n            features[safe_name] = _finite(safe_mag_ratio)\n\n    # Curvature terms.\n    u = _to_float(raw["u"])\n    g = _to_float(raw["g"])\n    r = _to_float(raw["r"])\n    i = _to_float(raw["i"])\n    z = _to_float(raw["z"])\n\n    features["c1"] = _finite(u - 2.0 * r + i)\n    features["c2"] = _finite(g - 2.0 * i + z)\n\n    # Redshift polynomial and controlled interactions.\n    redshift = _to_float(raw["redshift"])\n    zr = redshift.clip(lower=0.0)\n    z1 = np.log1p(zr.clip(upper=_ZR_MAX))\n    z2 = np.square(zr)\n    z3 = np.power(zr, 3.0)\n\n    features["z1"] = _finite(z1)\n    features["z2"] = _finite(z2)\n    features["z3"] = _finite(z3)\n\n    features["z1_x_lf_u"] = _finite(z1 * lf["u"])\n    features["z1_x_lf_g"] = _finite(z1 * lf["g"])\n    features["z2_x_ri"] = _finite(z2 * (r - i))\n    features["z3_x_gz"] = _finite(z3 * (g - z))\n\n    return pd.DataFrame(features, index=idx)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_broadband_flux_ratios",\n        "fn": add_aide_broadband_flux_ratios,\n        "depends_on": [],\n        "description": "Build clipped flux-domain, pairwise color, curvature, and redshift-interaction features from u,g,r,i,z magnitudes and redshift.",\n    }\n]'

HYPOTHESIS_000022_AUTOGLUON_004_PY_10E21EEB73_SOURCE = 'import numpy as np\nimport pandas as pd\nfrom collections import deque\n\n_AIDE_RA_BINS = 720\n_AIDE_DEC_BINS = 338\n_AIDE_SHRINKAGE_K = 20.0\n_AIDE_FALLBACK_THRESHOLD = 20\n_AIDE_REDSHIFT_MIN = 0.0\n_AIDE_REDSHIFT_MAX = 7.0\n_AIDE_EPS = 1e-6\n\n_AIDE_FEATURE_ORDER = (\n    "u",\n    "g",\n    "r",\n    "i",\n    "z",\n    "redshift_clipped",\n    "u_minus_g",\n    "g_minus_r",\n    "r_minus_i",\n    "i_minus_z",\n    "u_minus_i",\n    "u_minus_r",\n    "g_minus_z",\n    "r_minus_z",\n    "u_minus_2r_plus_i",\n    "g_minus_2i_plus_z",\n)\n\n_AIDE_COLOR_SHAPE_FEATURES = (\n    "u_minus_g",\n    "g_minus_r",\n    "r_minus_i",\n    "i_minus_z",\n    "u_minus_i",\n    "u_minus_r",\n    "g_minus_z",\n    "r_minus_z",\n    "u_minus_2r_plus_i",\n    "g_minus_2i_plus_z",\n)\n\n\ndef _safe_divide(numerator, denominator):\n    out = np.full_like(numerator, np.nan, dtype=np.float64)\n    mask = denominator > 0\n    out[mask] = numerator[mask] / denominator[mask]\n    return out\n\n\ndef _build_cell_index(alpha, delta):\n    alpha_clean = np.where(np.isfinite(alpha), alpha, 0.0)\n    delta_clean = np.where(np.isfinite(delta), delta, -90.0)\n\n    ra_bin = np.floor(np.mod(alpha_clean, 360.0) * 2.0).astype(np.int32)\n    ra_bin = np.clip(ra_bin, 0, _AIDE_RA_BINS - 1)\n\n    dec_bin = np.floor((delta_clean + 90.0) * 2.0).astype(np.int32)\n    dec_bin = np.clip(dec_bin, 0, _AIDE_DEC_BINS - 1)\n\n    cell_idx = ra_bin * _AIDE_DEC_BINS + dec_bin\n    return ra_bin, dec_bin, cell_idx\n\n\ndef _nearest_nonempty_lookup(cell_counts, ra_bins, dec_bins):\n    n_cells = ra_bins * dec_bins\n    nearest = np.full(n_cells, -1, dtype=np.int32)\n    dist = np.full(n_cells, -1, dtype=np.int32)\n\n    sources = np.flatnonzero(cell_counts > 0)\n    if sources.size == 0:\n        return nearest, dist\n\n    q = deque()\n    for src in sources:\n        nearest[src] = src\n        dist[src] = 0\n        q.append(src)\n\n    while q:\n        cur = q.popleft()\n        cur_ra = cur // dec_bins\n        cur_dec = cur - cur_ra * dec_bins\n        nd = dist[cur] + 1\n\n        ra_minus = cur_ra - 1\n        if ra_minus < 0:\n            ra_minus = ra_bins - 1\n        nb = ra_minus * dec_bins + cur_dec\n        if dist[nb] < 0:\n            dist[nb] = nd\n            nearest[nb] = nearest[cur]\n            q.append(nb)\n\n        ra_plus = cur_ra + 1\n        if ra_plus >= ra_bins:\n            ra_plus = 0\n        nb = ra_plus * dec_bins + cur_dec\n        if dist[nb] < 0:\n            dist[nb] = nd\n            nearest[nb] = nearest[cur]\n            q.append(nb)\n\n        if cur_dec > 0:\n            nb = cur_ra * dec_bins + (cur_dec - 1)\n            if dist[nb] < 0:\n                dist[nb] = nd\n                nearest[nb] = nearest[cur]\n                q.append(nb)\n\n        if cur_dec + 1 < dec_bins:\n            nb = cur_ra * dec_bins + (cur_dec + 1)\n            if dist[nb] < 0:\n                dist[nb] = nd\n                nearest[nb] = nearest[cur]\n                q.append(nb)\n\n    return nearest, dist\n\n\ndef _compute_cell_stats(values, cell_idx, n_cells):\n    values = np.asarray(values, dtype=np.float64)\n    finite = np.isfinite(values)\n    cell_mean = np.full(n_cells, np.nan, dtype=np.float64)\n    cell_std = np.full(n_cells, np.nan, dtype=np.float64)\n\n    if not np.any(finite):\n        return cell_mean, cell_std, np.nan, np.nan, _AIDE_EPS\n\n    idx = cell_idx[finite]\n    vals = values[finite]\n\n    counts = np.bincount(idx, weights=np.ones(vals.shape[0], dtype=np.float64), minlength=n_cells).astype(np.int32)\n    sums = np.bincount(idx, weights=vals, minlength=n_cells)\n    sumsq = np.bincount(idx, weights=vals * vals, minlength=n_cells)\n\n    valid = counts > 0\n    cell_mean[valid] = sums[valid] / counts[valid]\n\n    var = np.zeros(n_cells, dtype=np.float64)\n    var[valid] = np.maximum(sumsq[valid] / counts[valid] - cell_mean[valid] * cell_mean[valid], 0.0)\n    cell_std[valid] = np.sqrt(var[valid])\n\n    global_mean = np.mean(vals)\n    global_std = np.sqrt(np.mean((vals - global_mean) ** 2))\n\n    if np.any(valid):\n        cell_std_vals = cell_std[valid]\n        sigma_floor = np.nanpercentile(cell_std_vals, 0.1)\n        if not np.isfinite(sigma_floor) or sigma_floor <= _AIDE_EPS:\n            pos = cell_std_vals[cell_std_vals > _AIDE_EPS]\n            if pos.size > 0:\n                sigma_floor = np.nanpercentile(pos, 0.1)\n            elif np.isfinite(global_std) and global_std > _AIDE_EPS:\n                sigma_floor = global_std\n            else:\n                sigma_floor = _AIDE_EPS\n    else:\n        sigma_floor = _AIDE_EPS\n\n    if not np.isfinite(sigma_floor) or sigma_floor <= 0:\n        sigma_floor = _AIDE_EPS\n\n    return cell_mean, cell_std, global_mean, global_std, sigma_floor\n\n\ndef add_aide_sky_cell_local_residuals(raw, deps, aux):\n    alpha = pd.to_numeric(raw["alpha"], errors="coerce").to_numpy(dtype=np.float64)\n    delta = pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=np.float64)\n    idx = raw.index\n    n = len(raw)\n\n    if n == 0:\n        return pd.DataFrame(index=idx)\n\n    ra_bin, dec_bin, cell_idx = _build_cell_index(alpha, delta)\n    n_cells = _AIDE_RA_BINS * _AIDE_DEC_BINS\n\n    cell_counts = np.bincount(cell_idx, minlength=n_cells).astype(np.int32)\n    n_cell = cell_counts[cell_idx].astype(np.float64)\n\n    ra_minus = (ra_bin - 1) % _AIDE_RA_BINS\n    ra_plus = (ra_bin + 1) % _AIDE_RA_BINS\n    dec_minus = dec_bin - 1\n    dec_plus = dec_bin + 1\n\n    counts_grid = cell_counts.reshape(_AIDE_RA_BINS, _AIDE_DEC_BINS)\n\n    n_neigh = (\n        counts_grid[ra_bin, dec_bin]\n        + counts_grid[ra_minus, dec_bin]\n        + counts_grid[ra_plus, dec_bin]\n    ).astype(np.float64)\n\n    mid_mask = dec_bin > 0\n    if np.any(mid_mask):\n        n_neigh[mid_mask] += (\n            counts_grid[ra_minus[mid_mask], dec_minus[mid_mask]]\n            + counts_grid[ra_bin[mid_mask], dec_minus[mid_mask]]\n            + counts_grid[ra_plus[mid_mask], dec_minus[mid_mask]]\n        )\n\n    plus_mask = dec_plus < _AIDE_DEC_BINS\n    if np.any(plus_mask):\n        n_neigh[plus_mask] += (\n            counts_grid[ra_minus[plus_mask], dec_plus[plus_mask]]\n            + counts_grid[ra_bin[plus_mask], dec_plus[plus_mask]]\n            + counts_grid[ra_plus[plus_mask], dec_plus[plus_mask]]\n        )\n\n    concentration = n_cell / (n_neigh + _AIDE_EPS)\n\n    nearest_idx, nearest_dist = _nearest_nonempty_lookup(cell_counts, _AIDE_RA_BINS, _AIDE_DEC_BINS)\n    fallback_idx = nearest_idx[cell_idx].astype(np.int32)\n    fallback_dist = nearest_dist[cell_idx].astype(np.float64)\n\n    neighbor_cells = np.stack(\n        (\n            ra_minus * _AIDE_DEC_BINS + dec_minus,\n            ra_bin * _AIDE_DEC_BINS + dec_minus,\n            ra_plus * _AIDE_DEC_BINS + dec_minus,\n            ra_minus * _AIDE_DEC_BINS + dec_bin,\n            ra_plus * _AIDE_DEC_BINS + dec_bin,\n            ra_minus * _AIDE_DEC_BINS + dec_plus,\n            ra_bin * _AIDE_DEC_BINS + dec_plus,\n            ra_plus * _AIDE_DEC_BINS + dec_plus,\n        ),\n        axis=1,\n    )\n    neighbor_cells = np.where(\n        (neighbor_cells == cell_idx[:, None]) | (neighbor_cells < 0),\n        -1,\n        neighbor_cells,\n    )\n    neighbor_counts = np.where(neighbor_cells >= 0, cell_counts[neighbor_cells], -1)\n    neighbor_has = neighbor_counts > 0\n    neighbor_any = np.any(neighbor_has, axis=1)\n    neighbor_first = np.argmax(neighbor_has.astype(np.int8), axis=1)\n    neighbor_best = neighbor_cells[np.arange(n), neighbor_first]\n    neighbor_best = np.where(neighbor_any, neighbor_best, cell_idx)\n\n    sparse_mask = n_cell < float(_AIDE_FALLBACK_THRESHOLD)\n    use_alt = sparse_mask & (fallback_dist == 0.0) & neighbor_any\n\n    fallback_idx = np.where(use_alt, neighbor_best, fallback_idx)\n    fallback_dist = np.where(use_alt, 1.0, fallback_dist)\n\n    fallback_n_cell = cell_counts[fallback_idx].astype(np.float64)\n    fallback_w = fallback_n_cell / (fallback_n_cell + _AIDE_SHRINKAGE_K)\n    use_fallback = sparse_mask\n\n    u = pd.to_numeric(raw["u"], errors="coerce").to_numpy(dtype=np.float64)\n    g = pd.to_numeric(raw["g"], errors="coerce").to_numpy(dtype=np.float64)\n    r = pd.to_numeric(raw["r"], errors="coerce").to_numpy(dtype=np.float64)\n    i = pd.to_numeric(raw["i"], errors="coerce").to_numpy(dtype=np.float64)\n    z = pd.to_numeric(raw["z"], errors="coerce").to_numpy(dtype=np.float64)\n    redshift = pd.to_numeric(raw["redshift"], errors="coerce").to_numpy(dtype=np.float64)\n    redshift_clipped = np.clip(redshift, _AIDE_REDSHIFT_MIN, _AIDE_REDSHIFT_MAX)\n\n    feature_vals = {\n        "u": u,\n        "g": g,\n        "r": r,\n        "i": i,\n        "z": z,\n        "redshift_clipped": redshift_clipped,\n        "u_minus_g": u - g,\n        "g_minus_r": g - r,\n        "r_minus_i": r - i,\n        "i_minus_z": i - z,\n        "u_minus_i": u - i,\n        "u_minus_r": u - r,\n        "g_minus_z": g - z,\n        "r_minus_z": r - z,\n        "u_minus_2r_plus_i": u - 2.0 * r + i,\n        "g_minus_2i_plus_z": g - 2.0 * i + z,\n    }\n\n    color_set = set(_AIDE_COLOR_SHAPE_FEATURES)\n\n    local_delta_sum = np.zeros(n, dtype=np.float64)\n    local_delta_abs_sum = np.zeros(n, dtype=np.float64)\n    local_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    local_z_sum = np.zeros(n, dtype=np.float64)\n    local_z_abs_max = np.full(n, -np.inf, dtype=np.float64)\n    local_valid = np.zeros(n, dtype=np.int32)\n\n    local_color_delta_sum = np.zeros(n, dtype=np.float64)\n    local_color_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    local_color_valid = np.zeros(n, dtype=np.int32)\n\n    fallback_delta_sum = np.zeros(n, dtype=np.float64)\n    fallback_delta_abs_sum = np.zeros(n, dtype=np.float64)\n    fallback_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    fallback_z_sum = np.zeros(n, dtype=np.float64)\n    fallback_z_abs_max = np.full(n, -np.inf, dtype=np.float64)\n    fallback_valid = np.zeros(n, dtype=np.int32)\n\n    fallback_color_delta_sum = np.zeros(n, dtype=np.float64)\n    fallback_color_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    fallback_color_valid = np.zeros(n, dtype=np.int32)\n\n    new_features = {}\n\n    for feat in _AIDE_FEATURE_ORDER:\n        vals = feature_vals[feat]\n        finite = np.isfinite(vals)\n\n        cell_mean, cell_std, global_mean, global_std, sigma_floor = _compute_cell_stats(vals, cell_idx, n_cells)\n\n        mu_local = (\n            n_cell * cell_mean[cell_idx] / (n_cell + _AIDE_SHRINKAGE_K)\n            + (1.0 - n_cell / (n_cell + _AIDE_SHRINKAGE_K)) * global_mean\n        )\n        sigma_local = (\n            n_cell * cell_std[cell_idx] / (n_cell + _AIDE_SHRINKAGE_K)\n            + (1.0 - n_cell / (n_cell + _AIDE_SHRINKAGE_K)) * global_std\n        )\n        sigma_local = np.where(np.isfinite(sigma_local), sigma_local, sigma_floor)\n        sigma_local = np.where(sigma_local < sigma_floor, sigma_floor, sigma_local)\n\n        local_delta = np.full(n, np.nan, dtype=np.float64)\n        local_z = np.full(n, np.nan, dtype=np.float64)\n\n        valid_local = finite & np.isfinite(mu_local) & np.isfinite(sigma_local)\n        if np.any(valid_local):\n            local_delta[valid_local] = vals[valid_local] - mu_local[valid_local]\n            local_z[valid_local] = local_delta[valid_local] / (sigma_local[valid_local] + _AIDE_EPS)\n\n            d = local_delta[valid_local]\n            zv = local_z[valid_local]\n\n            local_delta_sum[valid_local] += d\n            local_delta_abs_sum[valid_local] += np.abs(d)\n            local_delta_sq_sum[valid_local] += d * d\n            local_z_sum[valid_local] += zv\n            local_z_abs_max[valid_local] = np.maximum(local_z_abs_max[valid_local], np.abs(zv))\n            local_valid[valid_local] += 1\n\n            if feat in color_set:\n                local_color_delta_sum[valid_local] += d\n                local_color_delta_sq_sum[valid_local] += d * d\n                local_color_valid[valid_local] += 1\n\n        mu_fb = (\n            fallback_w * cell_mean[fallback_idx]\n            + (1.0 - fallback_w) * global_mean\n        )\n        sigma_fb = (\n            fallback_w * cell_std[fallback_idx]\n            + (1.0 - fallback_w) * global_std\n        )\n        sigma_fb = np.where(np.isfinite(sigma_fb), sigma_fb, sigma_floor)\n        sigma_fb = np.where(sigma_fb < sigma_floor, sigma_floor, sigma_fb)\n\n        fallback_delta = np.full(n, np.nan, dtype=np.float64)\n        fallback_z = np.full(n, np.nan, dtype=np.float64)\n\n        valid_fb = use_fallback & finite & np.isfinite(mu_fb) & np.isfinite(sigma_fb)\n        if np.any(valid_fb):\n            fallback_delta[valid_fb] = vals[valid_fb] - mu_fb[valid_fb]\n            fallback_z[valid_fb] = fallback_delta[valid_fb] / (sigma_fb[valid_fb] + _AIDE_EPS)\n\n            d_fb = fallback_delta[valid_fb]\n            z_fb = fallback_z[valid_fb]\n\n            fallback_delta_sum[valid_fb] += d_fb\n            fallback_delta_abs_sum[valid_fb] += np.abs(d_fb)\n            fallback_delta_sq_sum[valid_fb] += d_fb * d_fb\n            fallback_z_sum[valid_fb] += z_fb\n            fallback_z_abs_max[valid_fb] = np.maximum(fallback_z_abs_max[valid_fb], np.abs(z_fb))\n            fallback_valid[valid_fb] += 1\n\n            if feat in color_set:\n                fallback_color_delta_sum[valid_fb] += d_fb\n                fallback_color_delta_sq_sum[valid_fb] += d_fb * d_fb\n                fallback_color_valid[valid_fb] += 1\n\n        new_features[f"{feat}_cell_delta"] = local_delta\n        new_features[f"{feat}_cell_z"] = local_z\n\n    local_delta_mean = _safe_divide(local_delta_sum, local_valid.astype(np.float64))\n    local_delta_abs_mean = _safe_divide(local_delta_abs_sum, local_valid.astype(np.float64))\n    local_z_mean = _safe_divide(local_z_sum, local_valid.astype(np.float64))\n    local_delta_l2 = np.sqrt(local_delta_sq_sum)\n    local_z_abs_max = np.where(local_valid > 0, local_z_abs_max, np.nan)\n\n    local_color_mean = _safe_divide(local_color_delta_sum, local_color_valid.astype(np.float64))\n    local_color_var = _safe_divide(local_color_delta_sq_sum, local_color_valid.astype(np.float64)) - local_color_mean * local_color_mean\n    local_color_var = np.where(local_color_var < 0.0, 0.0, local_color_var)\n    local_shape_resid_std = np.full(n, np.nan, dtype=np.float64)\n    color_mask = local_color_valid > 0\n    local_shape_resid_std[color_mask] = np.sqrt(local_color_var[color_mask])\n\n    fallback_delta_mean = _safe_divide(fallback_delta_sum, fallback_valid.astype(np.float64))\n    fallback_delta_abs_mean = _safe_divide(fallback_delta_abs_sum, fallback_valid.astype(np.float64))\n    fallback_z_mean = _safe_divide(fallback_z_sum, fallback_valid.astype(np.float64))\n    fallback_delta_l2 = np.sqrt(fallback_delta_sq_sum)\n    fallback_z_abs_max = np.where(fallback_valid > 0, fallback_z_abs_max, np.nan)\n\n    fallback_color_mean = _safe_divide(fallback_color_delta_sum, fallback_color_valid.astype(np.float64))\n    fallback_color_var = _safe_divide(fallback_color_delta_sq_sum, fallback_color_valid.astype(np.float64)) - fallback_color_mean * fallback_color_mean\n    fallback_color_var = np.where(fallback_color_var < 0.0, 0.0, fallback_color_var)\n    fallback_shape_resid_std = np.full(n, np.nan, dtype=np.float64)\n    fb_color_mask = fallback_color_valid > 0\n    fallback_shape_resid_std[fb_color_mask] = np.sqrt(fallback_color_var[fb_color_mask])\n\n    cell_alpha_center = (ra_bin.astype(np.float64) + 0.5) * 0.5\n    cell_delta_center = (dec_bin.astype(np.float64) + 0.5) * 0.5 - 90.0\n\n    new_features.update(\n        {\n            "sky_cell_ra_bin": ra_bin.astype(np.float64),\n            "sky_cell_dec_bin": dec_bin.astype(np.float64),\n            "sky_cell_ra_center": cell_alpha_center,\n            "sky_cell_dec_center": cell_delta_center,\n            "sky_cell_n": n_cell,\n            "sky_cell_n_neigh": n_neigh,\n            "sky_cell_concentration": concentration,\n            "sky_cell_is_sparse": sparse_mask.astype(np.int8),\n            "sky_cell_fallback_used": use_fallback.astype(np.int8),\n            "sky_cell_fallback_dist": np.where(use_fallback, fallback_dist, np.nan),\n            "sky_cell_fallback_cell_n": np.where(use_fallback, fallback_n_cell, np.nan),\n            "sky_cell_local_delta_mean": local_delta_mean,\n            "sky_cell_local_delta_abs_mean": local_delta_abs_mean,\n            "sky_cell_local_delta_l1": local_delta_abs_sum,\n            "sky_cell_local_delta_l2": local_delta_l2,\n            "sky_cell_local_z_mean": local_z_mean,\n            "sky_cell_local_abs_z_max": local_z_abs_max,\n            "sky_cell_local_shape_resid_std": local_shape_resid_std,\n            "sky_cell_local_n_features": local_valid.astype(np.float64),\n            "sky_cell_fallback_delta_mean": fallback_delta_mean,\n            "sky_cell_fallback_delta_abs_mean": fallback_delta_abs_mean,\n            "sky_cell_fallback_delta_l1": fallback_delta_abs_sum,\n            "sky_cell_fallback_delta_l2": fallback_delta_l2,\n            "sky_cell_fallback_z_mean": fallback_z_mean,\n            "sky_cell_fallback_abs_z_max": fallback_z_abs_max,\n            "sky_cell_fallback_shape_resid_std": fallback_shape_resid_std,\n            "sky_cell_fallback_n_features": fallback_valid.astype(np.float64),\n        }\n    )\n\n    return pd.DataFrame(new_features, index=idx)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_sky_cell_local_residuals",\n        "fn": add_aide_sky_cell_local_residuals,\n        "depends_on": [],\n        "description": "Spatial sky-cell residualization with shrinkage to local cell/global statistics and sparse-cell neighborhood fallback features.",\n    }\n]'

HYPOTHESIS_000023_AUTOGLUON_003_PY_24CE3BC884_SOURCE = 'import numpy as np\nimport pandas as pd\nfrom pandas.api.types import is_bool_dtype, is_numeric_dtype, is_object_dtype, is_string_dtype\n\nEPS = 1e-6\nCHANNEL_NAMES = (\n    "u_minus_g",\n    "g_minus_r",\n    "r_minus_i",\n    "i_minus_z",\n    "u_minus_i",\n    "u_minus_r",\n    "g_minus_z",\n    "r_minus_z",\n    "u_minus_2r_plus_i",\n    "g_minus_2i_plus_z",\n)\nCHANNEL_COUNT = 10\n\n\ndef _coerce_bool_mask(values, n_rows):\n    if values is None or len(values) != n_rows:\n        return None\n\n    ser = pd.Series(values)\n\n    if is_bool_dtype(ser):\n        if ser.isna().all():\n            return None\n        return ser.fillna(False).to_numpy(dtype=bool)\n\n    if is_numeric_dtype(ser):\n        vals = pd.to_numeric(ser, errors="coerce")\n        unique = pd.Index(vals.dropna().unique())\n        if unique.empty:\n            return None\n        if unique.isin([0, 1]).all():\n            return vals.fillna(0).astype(np.int8).astype(bool).to_numpy()\n\n    if is_object_dtype(ser) or is_string_dtype(ser):\n        lowered = ser.dropna().astype(str).str.strip().str.lower()\n        unique = set(lowered.unique())\n        if not unique:\n            return None\n        if {"train", "val", "validation", "test"}.intersection(unique):\n            if "train" in unique:\n                return lowered.eq("train").to_numpy(dtype=bool)\n            if "validation" in unique or "val" in unique:\n                return lowered.isin({"train", "validation", "val"}).to_numpy(dtype=bool)\n        if {"0", "1"}.issubset(unique) and unique.issubset({"0", "1", "true", "false", "t", "f", "yes", "no", "y", "n"}):\n            return lowered.isin(["1", "true", "t", "yes", "y"]).to_numpy(dtype=bool)\n\n    return None\n\n\ndef _infer_train_mask(raw, aux):\n    n_rows = len(raw)\n    if aux is not None and isinstance(aux, pd.DataFrame) and not aux.empty and len(aux) == n_rows:\n        preferred_cols = ("is_train", "is_train_mask", "train_mask", "train", "train_indicator", "train_flag")\n        for col in preferred_cols:\n            if col in aux.columns:\n                mask = _coerce_bool_mask(aux[col], n_rows)\n                if mask is not None and mask.ndim == 1 and mask.size == n_rows and mask.any():\n                    return mask\n\n        for col in aux.columns:\n            mask = _coerce_bool_mask(aux[col], n_rows)\n            if mask is not None and mask.ndim == 1 and mask.size == n_rows and mask.any():\n                return mask\n\n    if "is_train" in raw.columns:\n        mask = _coerce_bool_mask(raw["is_train"], n_rows)\n        if mask is not None and mask.any():\n            return mask\n\n    fallback = np.ones(n_rows, dtype=bool)\n    if "id" in raw.columns:\n        ids = pd.to_numeric(raw["id"], errors="coerce")\n        if ids.notna().all():\n            if np.isfinite(ids.min()) and np.isfinite(ids.max()):\n                # For datasets with contiguous train ids first, keep the largest likely training block.\n                n_unique = ids.nunique(dropna=False)\n                if ids.min() >= 0 and float(n_unique) == float(ids.max() - ids.min() + 1):\n                    return np.asarray(ids <= ids.quantile(0.7), dtype=bool)\n\n    return fallback\n\n\ndef _build_bin_edges(redshift_train):\n    edges = np.quantile(redshift_train, np.linspace(0.0, 1.0, 25))\n    edges = np.unique(np.asarray(edges, dtype=np.float64))\n    if edges.size < 13:\n        zmin = float(np.nanmin(redshift_train))\n        zmax = float(np.nanmax(redshift_train))\n        if zmin == zmax:\n            eps = 1e-6 if zmin == 0.0 else abs(zmin) * 1e-6\n            if eps == 0.0:\n                eps = 1e-6\n            zmin -= eps\n            zmax += eps\n        edges = np.linspace(zmin, zmax, 25)\n        edges = np.unique(edges)\n\n    if edges.size < 2:\n        zmin = float(np.nanmin(redshift_train))\n        zmax = float(np.nanmax(redshift_train))\n        if zmin == zmax:\n            eps = 1e-6\n            edges = np.array([zmin - eps, zmax + eps], dtype=np.float64)\n        else:\n            edges = np.array([zmin, zmax], dtype=np.float64)\n\n    return edges\n\n\ndef add_aide_redshift_bin_color_residuals(raw, deps, aux):\n    redshift = raw["redshift"].to_numpy(dtype=np.float64, copy=False)\n    z0 = np.clip(redshift, 0.0, 7.01)\n\n    train_mask = _infer_train_mask(raw, aux)\n    if not np.any(train_mask):\n        train_mask = np.ones(len(raw), dtype=bool)\n\n    redshift_train = z0[train_mask]\n    if redshift_train.size == 0:\n        redshift_train = z0\n\n    edges = _build_bin_edges(redshift_train)\n    num_bins = edges.size - 1\n    if num_bins < 1:\n        edges = np.array([0.0, 7.01], dtype=np.float64)\n        num_bins = 1\n\n    bins = np.searchsorted(edges, z0, side="right") - 1\n    bins = np.clip(bins, 0, num_bins - 1).astype(np.int32)\n\n    u = raw["u"].to_numpy(dtype=np.float64, copy=False)\n    g = raw["g"].to_numpy(dtype=np.float64, copy=False)\n    r = raw["r"].to_numpy(dtype=np.float64, copy=False)\n    i = raw["i"].to_numpy(dtype=np.float64, copy=False)\n    z = raw["z"].to_numpy(dtype=np.float64, copy=False)\n\n    channels = np.column_stack(\n        (\n            u - g,\n            g - r,\n            r - i,\n            i - z,\n            u - i,\n            u - r,\n            g - z,\n            r - z,\n            u - 2.0 * r + i,\n            g - 2.0 * i + z,\n        )\n    )\n\n    n_rows = channels.shape[0]\n    residual_sum_sq = np.zeros(n_rows, dtype=np.float64)\n    residual_sum_abs = np.zeros(n_rows, dtype=np.float64)\n    residual_sum = np.zeros(n_rows, dtype=np.float64)\n    residual_sum_sq_raw = np.zeros(n_rows, dtype=np.float64)\n    standardized_sum = np.zeros(n_rows, dtype=np.float64)\n    standardized_maxabs = np.zeros(n_rows, dtype=np.float64)\n\n    train_bins = bins[train_mask]\n    for c in range(CHANNEL_COUNT):\n        ch = channels[:, c]\n        ch_train = ch[train_mask]\n\n        mu_b = np.zeros(num_bins, dtype=np.float64)\n        sigma_b = np.zeros(num_bins, dtype=np.float64)\n        n_b = np.zeros(num_bins, dtype=np.float64)\n\n        for b in range(num_bins):\n            sel = train_bins == b\n            if np.any(sel):\n                vals = ch_train[sel]\n                n = vals.shape[0]\n                n_b[b] = n\n                mu_b[b] = np.mean(vals)\n                sigma_b[b] = np.std(vals, ddof=1) if n > 1 else 0.0\n            else:\n                mu_b[b] = 0.0\n                sigma_b[b] = 0.0\n\n        if ch_train.size > 0:\n            mu_all = float(np.mean(ch_train))\n            sigma_all = float(np.std(ch_train, ddof=1)) if ch_train.size > 1 else 0.0\n        else:\n            mu_all = 0.0\n            sigma_all = 0.0\n\n        w = np.minimum(1.0, n_b / 400.0)\n        mu_tilde = w * mu_b + (1.0 - w) * mu_all\n        sigma_tilde = w * sigma_b + (1.0 - w) * sigma_all\n        sigma_tilde = np.maximum(sigma_tilde, EPS)\n\n        d = ch - mu_tilde[bins]\n        s = d / sigma_tilde[bins]\n\n        residual_sum_sq += d * d\n        residual_sum_abs += np.abs(d)\n        residual_sum += d\n        residual_sum_sq_raw += d * d\n        standardized_sum += s\n        standardized_maxabs = np.maximum(standardized_maxabs, np.abs(s))\n\n    mean_d = residual_sum / float(CHANNEL_COUNT)\n    mean_abs_d = residual_sum_abs / float(CHANNEL_COUNT)\n    var_d = residual_sum_sq_raw / float(CHANNEL_COUNT) - mean_d * mean_d\n    var_d = np.maximum(var_d, 0.0)\n    std_d = np.sqrt(var_d)\n\n    features = pd.DataFrame(\n        {\n            "aide_redshift_resid_root_sum_sq": np.sqrt(residual_sum_sq),\n            "aide_redshift_resid_mean_abs": mean_abs_d,\n            "aide_redshift_resid_mean": mean_d,\n            "aide_redshift_resid_std": std_d,\n            "aide_redshift_resid_std_mean": standardized_sum / float(CHANNEL_COUNT),\n            "aide_redshift_resid_max_abs_std": standardized_maxabs,\n        },\n        index=raw.index,\n    )\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_redshift_bin_color_residuals",\n        "fn": add_aide_redshift_bin_color_residuals,\n        "depends_on": [],\n        "description": "Build redshift-conditioned residual and standardized-residual summaries over fixed AIDE color/curvature channels.",\n    }\n]'

HYPOTHESIS_000024_AUTOGLUON_002_PY_002343048C_SOURCE = 'import numpy as np\nimport pandas as pd\n\nNUMERIC_BANDS = ("u", "g", "r", "i", "z")\nQUANTILE_BINS = 12\nCLIP_QUANTILE = 0.999\nRANK_METHOD = "average"\n\n\ndef add_aide_catalog_rank_frequency_context(raw, deps, aux):\n    spectrum = raw["spectral_type"].astype("string")\n    population = raw["galaxy_population"].astype("string")\n    spectrum_population = spectrum.str.cat(population, sep="|")\n    row_count = float(len(raw))\n\n    features = pd.DataFrame(index=raw.index)\n\n    spectrum_freq = spectrum.value_counts(dropna=False) / row_count\n    population_freq = population.value_counts(dropna=False) / row_count\n    pair_freq = spectrum_population.value_counts(dropna=False) / row_count\n\n    features["spectral_type_freq"] = spectrum.map(spectrum_freq).astype(np.float64)\n    features["galaxy_population_freq"] = population.map(population_freq).astype(np.float64)\n    features["spectral_population_pair_freq"] = spectrum_population.map(pair_freq).astype(np.float64)\n\n    redshift_nonneg = raw["redshift"].clip(lower=0.0)\n    redshift_clipped = redshift_nonneg.clip(upper=float(redshift_nonneg.quantile(CLIP_QUANTILE))\n    )\n    redshift_log1p = np.log1p(redshift_clipped)\n    redshift_log1p_clipped = redshift_log1p.clip(\n        upper=float(redshift_log1p.quantile(CLIP_QUANTILE))\n    )\n\n    numeric_series = {\n        "u": raw["u"],\n        "g": raw["g"],\n        "r": raw["r"],\n        "i": raw["i"],\n        "z": raw["z"],\n        "redshift_clipped": redshift_clipped,\n        "redshift_log1p_clipped": redshift_log1p_clipped,\n    }\n\n    global_rank_cols = []\n    within_spectrum_rank_cols = []\n    within_population_rank_cols = []\n\n    for name, values in numeric_series.items():\n        global_rank = values.rank(method=RANK_METHOD, pct=True)\n        qbin = pd.qcut(\n            values,\n            q=QUANTILE_BINS,\n            labels=False,\n            duplicates="drop",\n        )\n        qbin_freq = qbin.value_counts(normalize=True).sort_index()\n\n        features[f"{name}_global_percentile"] = global_rank.astype(np.float64)\n        features[f"{name}_quantile_bin12"] = qbin.astype("float64")\n        features[f"{name}_quantile_bin_freq12"] = qbin.map(qbin_freq).astype(np.float64)\n\n        within_spectrum_rank = values.groupby(spectrum, sort=False).rank(method=RANK_METHOD, pct=True)\n        within_population_rank = values.groupby(population, sort=False).rank(method=RANK_METHOD, pct=True)\n\n        features[f"{name}_spectrum_within_percentile"] = within_spectrum_rank.astype(np.float64)\n        features[f"{name}_population_within_percentile"] = within_population_rank.astype(np.float64)\n\n        global_rank_cols.append(f"{name}_global_percentile")\n        within_spectrum_rank_cols.append(f"{name}_spectrum_within_percentile")\n        within_population_rank_cols.append(f"{name}_population_within_percentile")\n\n    features["global_rank_mean"] = features[global_rank_cols].mean(axis=1)\n    features["global_rank_std"] = features[global_rank_cols].std(axis=1, ddof=0)\n    features["spectrum_within_rank_mean"] = features[within_spectrum_rank_cols].mean(axis=1)\n    features["spectrum_within_rank_std"] = features[within_spectrum_rank_cols].std(axis=1, ddof=0)\n    features["population_within_rank_mean"] = features[within_population_rank_cols].mean(axis=1)\n    features["population_within_rank_std"] = features[within_population_rank_cols].std(axis=1, ddof=0)\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_catalog_rank_frequency_context",\n        "fn": add_aide_catalog_rank_frequency_context,\n        "depends_on": [],\n        "description": "Adds AIDE-style catalog-frequency and percentile/rank context using spectral/generic categories and photometric/redshift quantiles.",\n    }\n]'

HYPOTHESIS_000025_AUTOGLUON_002_PY_8279AF7E20_SOURCE = 'import numpy as np\nimport pandas as pd\n\nAUX_REFERENCE_COLUMNS = ("alpha", "delta", "u", "g", "r", "i", "z", "redshift")\nPHOTOMETRY_COLUMNS = ("u", "g", "r", "i", "z")\nFEATURE_GROUP_NAME = "aide_aux_reference_distribution_distance"\nMAD_TO_STD = 1.482602218505602\nMAHALANOBIS_INLIER_QUANTILE = 0.975\n\n\ndef _to_float_array(series):\n    return pd.to_numeric(series, errors="coerce").to_numpy(dtype="float64", copy=True)\n\n\ndef _prepare_reference_series(aux, column):\n    values = _to_float_array(aux[column])\n    if column in PHOTOMETRY_COLUMNS:\n        values[values <= -9000.0] = np.nan\n    if column == "redshift":\n        finite = np.isfinite(values)\n        values[finite] = np.maximum(values[finite], 0.0)\n    return values\n\n\ndef _prepare_raw_series(raw, column):\n    values = _to_float_array(raw[column])\n    if column in PHOTOMETRY_COLUMNS:\n        values[values <= -9000.0] = np.nan\n    if column == "redshift":\n        finite = np.isfinite(values)\n        values[finite] = np.maximum(values[finite], 0.0)\n    return values\n\n\ndef _robust_center_and_scale(values):\n    finite = np.isfinite(values)\n    if not np.any(finite):\n        return np.nan, np.nan\n    center = np.median(values[finite])\n    mad = np.median(np.abs(values[finite] - center))\n    if not np.isfinite(mad) or mad <= 0.0:\n        return center, np.nan\n    return center, mad * MAD_TO_STD\n\n\ndef _robust_z(values, center, scale):\n    z = np.full(len(values), np.nan, dtype=np.float64)\n    if np.isfinite(center) and np.isfinite(scale) and scale > 0.0:\n        finite = np.isfinite(values)\n        z[finite] = (values[finite] - center) / scale\n    return z\n\n\ndef _empirical_cdf_position(reference_values, query_values):\n    finite_reference = np.isfinite(reference_values)\n    ref = np.sort(reference_values[finite_reference])\n    out = np.full(len(query_values), np.nan, dtype=np.float64)\n    if ref.size == 0:\n        return out\n    finite_query = np.isfinite(query_values)\n    if not np.any(finite_query):\n        return out\n    pos = np.searchsorted(ref, query_values[finite_query], side="right")\n    out[finite_query] = pos.astype(np.float64) / float(ref.size)\n    return out\n\n\ndef _mahalanobis_from_standardized(ref_standardized):\n    complete = np.isfinite(ref_standardized).all(axis=1)\n    ref_complete = ref_standardized[complete]\n    if ref_complete.shape[0] < 2 or ref_complete.shape[1] < 1:\n        return None, ref_complete\n    cov = np.cov(ref_complete, rowvar=False)\n    if np.ndim(cov) == 0:\n        cov = np.array([[float(cov)]], dtype=np.float64)\n    return np.linalg.pinv(cov), ref_complete\n\n\ndef add_aide_aux_reference_distribution_distance(raw, deps, aux):\n    _ = deps\n    idx = raw.index\n    n_rows = len(raw)\n\n    feature_data = {}\n\n    overlapping_columns = [col for col in AUX_REFERENCE_COLUMNS if col in raw.columns]\n    has_aux = isinstance(aux, pd.DataFrame) and aux.shape[0] > 0\n\n    ref_standardized_parts = []\n    raw_standardized_parts = []\n    z_components_for_l2 = []\n\n    for column in overlapping_columns:\n        raw_values = _prepare_raw_series(raw, column)\n        cdf_col = np.full(n_rows, 0.5, dtype=np.float64)\n        z_col = np.zeros(n_rows, dtype=np.float64)\n        delta_col = np.zeros(n_rows, dtype=np.float64)\n\n        if has_aux and column in aux.columns:\n            ref_values = _prepare_reference_series(aux, column)\n            center, scale = _robust_center_and_scale(ref_values)\n\n            if np.isfinite(center):\n                cdf_col = _empirical_cdf_position(ref_values, raw_values)\n                z_col = _robust_z(raw_values, center, scale)\n                finite = np.isfinite(raw_values)\n                delta_col = np.zeros(n_rows, dtype=np.float64)\n                delta_col[finite] = np.abs(raw_values[finite] - center)\n\n                if np.isfinite(scale) and scale > 0.0:\n                    ref_standardized = _robust_z(ref_values, center, scale)\n                    raw_standardized = _robust_z(raw_values, center, scale)\n                    ref_standardized_parts.append(ref_standardized[:, None])\n                    raw_standardized_parts.append(raw_standardized[:, None])\n\n        feature_data[f"cdf_{column}"] = cdf_col\n        feature_data[f"robust_z_{column}"] = z_col\n        feature_data[f"abs_delta_from_ref_median_{column}"] = delta_col\n        z_components_for_l2.append(z_col)\n\n    if z_components_for_l2:\n        z_stack = np.column_stack(z_components_for_l2)\n        feature_data["joint_l2_robust_z"] = np.sqrt(np.nansum(np.square(z_stack), axis=1))\n    else:\n        feature_data["joint_l2_robust_z"] = np.zeros(n_rows, dtype=np.float64)\n\n    mahal2 = np.zeros(n_rows, dtype=np.float64)\n    mahal = np.zeros(n_rows, dtype=np.float64)\n    mahal_inlier = np.ones(n_rows, dtype=np.int8)\n\n    if ref_standardized_parts:\n        ref_matrix = np.column_stack(ref_standardized_parts)\n        raw_matrix = np.column_stack(raw_standardized_parts)\n        inv_cov, ref_complete = _mahalanobis_from_standardized(ref_matrix)\n        if inv_cov is not None and ref_complete.shape[0] > 0:\n            aux_tmp = np.dot(ref_complete, inv_cov)\n            aux_mahal2 = np.einsum("ij,ij->i", aux_tmp, ref_complete)\n            aux_mahal2 = np.maximum(aux_mahal2, 0.0)\n            finite_aux = np.isfinite(aux_mahal2)\n            if np.any(finite_aux):\n                cutoff = np.quantile(aux_mahal2[finite_aux], MAHALANOBIS_INLIER_QUANTILE)\n                raw_complete = np.isfinite(raw_matrix).all(axis=1)\n                if np.any(raw_complete):\n                    raw_tmp = np.dot(raw_matrix[raw_complete], inv_cov)\n                    raw_mahal2 = np.einsum("ij,ij->i", raw_tmp, raw_matrix[raw_complete])\n                    raw_mahal2 = np.maximum(raw_mahal2, 0.0)\n                    mahal2[raw_complete] = raw_mahal2\n                    mahal[raw_complete] = np.sqrt(raw_mahal2)\n                    mahal_inlier[raw_complete] = (raw_mahal2 <= cutoff).astype(np.int8)\n\n    feature_data["mahalanobis2_reference"] = mahal2\n    feature_data["mahalanobis_reference"] = mahal\n    feature_data["mahalanobis_inlier_reference"] = mahal_inlier\n\n    return pd.DataFrame(feature_data, index=idx)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": FEATURE_GROUP_NAME,\n        "fn": add_aide_aux_reference_distribution_distance,\n        "depends_on": [],\n        "description": "Compare each row against auxiliary reference columns with robust CDF position, robust z-score, median-delta, joint robust-z L2, and robust Mahalanobis distance features.",\n    }\n]'

HYPOTHESIS_000026_AUTOGLUON_004_PY_55FDD09202_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_GROUP_NAME = "aide_smooth_spline_sed_interactions"\n_ALPHA_KNOTS = 7\n_OTHER_KNOTS = 5\n_BSPLINE_DEGREE = 3\n_INTERACTION_BASIS = 2\n\n\ndef _coerce_series(values):\n    return pd.to_numeric(values, errors="coerce")\n\n\ndef _bounds_from_series(main_series, auxiliary_series=None):\n    combined = main_series if auxiliary_series is None else pd.concat([main_series, auxiliary_series], ignore_index=True)\n    arr = combined.to_numpy(dtype=float)\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        arr = main_series.to_numpy(dtype=float)\n        finite = np.isfinite(arr)\n    if not np.any(finite):\n        return 0.0, 1.0\n    lo = float(np.nanmin(arr[finite]))\n    hi = float(np.nanmax(arr[finite]))\n    if not np.isfinite(lo) or not np.isfinite(hi) or hi <= lo:\n        return 0.0, 1.0\n    return lo, hi\n\n\ndef _difference_series(raw_df, aux_df, left_col, right_col):\n    left = _coerce_series(raw_df[left_col])\n    right = _coerce_series(raw_df[right_col])\n    raw_series = left - right\n    aux_series = None\n    if isinstance(aux_df, pd.DataFrame) and not aux_df.empty and left_col in aux_df.columns and right_col in aux_df.columns:\n        left_aux = _coerce_series(aux_df[left_col])\n        right_aux = _coerce_series(aux_df[right_col])\n        aux_series = left_aux - right_aux\n    return raw_series, aux_series\n\n\ndef _manual_bspline_basis(values, lower, upper, n_internal_knots, degree=_BSPLINE_DEGREE):\n    x = np.asarray(values, dtype=float)\n    n = len(x)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower or n == 0:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(x)\n        out[finite, 0] = 1.0\n        return out\n\n    n_internal = max(2, int(n_internal_knots))\n    internal = np.linspace(lower, upper, n_internal + 2)[1:-1]\n    knots = np.r_[np.repeat(lower, degree + 1), internal, np.repeat(upper, degree + 1)]\n    n_basis = len(knots) - degree - 1\n    out = np.full((n, n_basis), np.nan, dtype=np.float32)\n\n    finite = np.isfinite(x)\n    if not np.any(finite):\n        return out\n\n    xv = x.copy()\n    xv[~finite] = lower\n    xv = np.clip(xv, lower, upper)\n    xi = xv[finite]\n    m = len(knots)\n    N = np.zeros((len(xi), m - 1), dtype=np.float64)\n\n    left = xi[:, None] >= knots[:-1][None, :]\n    right = xi[:, None] < knots[1:][None, :]\n    N[:, : m - 1] = (left & right).astype(np.float64)\n    N[xi == upper, n_basis - 1] = 1.0\n\n    for d in range(1, degree + 1):\n        n_cols = m - d - 1\n        N_next = np.zeros((len(xi), n_cols), dtype=np.float64)\n        for i in range(n_cols):\n            d1 = knots[i + d] - knots[i]\n            d2 = knots[i + d + 1] - knots[i + 1]\n            left_term = 0.0\n            right_term = 0.0\n            if d1 != 0.0:\n                left_term = ((xi - knots[i]) / d1) * N[:, i]\n            if d2 != 0.0:\n                right_term = ((knots[i + d + 1] - xi) / d2) * N[:, i + 1]\n            N_next[:, i] = left_term + right_term\n        N = N_next\n\n    finite_idx = np.flatnonzero(finite)\n    out[finite_idx] = N.astype(np.float32)\n    return out\n\n\ndef _nonperiodic_cubic_basis(values, lower, upper, n_knots):\n    arr = _coerce_series(values).to_numpy(dtype=float)\n    n = len(arr)\n    n_knots = int(max(2, n_knots))\n    if n == 0:\n        return np.empty((0, 0), dtype=np.float32)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(arr)\n        out[finite, 0] = 1.0\n        return out\n\n    internal = np.linspace(lower, upper, n_knots + 2)[1:-1]\n    knots = np.r_[np.repeat(lower, _BSPLINE_DEGREE + 1), internal, np.repeat(upper, _BSPLINE_DEGREE + 1)]\n    n_basis = len(knots) - _BSPLINE_DEGREE - 1\n    out = np.full((n, n_basis), np.nan, dtype=np.float32)\n\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        return out\n\n    x = np.clip(arr[finite], lower, upper)\n    try:\n        from scipy.interpolate import BSpline\n\n        coeff = np.eye(n_basis)\n        spline = BSpline(knots, coeff, _BSPLINE_DEGREE, axis=0, extrapolate=False)\n        basis = spline(x).astype(np.float64)\n    except Exception:\n        basis = _manual_bspline_basis(arr[finite], lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n\n    if basis.ndim == 1:\n        basis = basis[:, None]\n    finite_idx = np.flatnonzero(finite)\n    out[finite_idx] = basis.astype(np.float32)\n    return out\n\n\ndef _periodic_cubic_basis(values, lower, upper, n_knots):\n    arr = _coerce_series(values).to_numpy(dtype=float)\n    n = len(arr)\n    n_knots = int(max(3, n_knots))\n    if n == 0:\n        return np.empty((0, 0), dtype=np.float32)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(arr)\n        out[finite, 0] = 1.0\n        return out\n\n    out = np.full((n, n_knots), np.nan, dtype=np.float32)\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        return out\n\n    period = upper - lower\n    if not np.isfinite(period) or period <= 0.0:\n        fallback = _manual_bspline_basis(arr[finite], lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n        fallback = np.asarray(fallback, dtype=np.float32)\n        if fallback.shape[1] >= n_knots:\n            fallback = fallback[:, :n_knots]\n        else:\n            pad = np.full((fallback.shape[0], n_knots - fallback.shape[1]), np.nan, dtype=np.float32)\n            fallback = np.concatenate([fallback, pad], axis=1)\n        out[np.flatnonzero(finite)] = fallback\n        return out\n\n    xw = ((arr[finite] - lower) % period) + lower\n    try:\n        from scipy.interpolate import CubicSpline\n\n        nodes = np.linspace(lower, upper, n_knots + 1)\n        y = np.zeros((len(nodes), n_knots), dtype=float)\n        for i in range(n_knots):\n            y[i, i] = 1.0\n            if i == 0:\n                y[-1, i] = 1.0\n        spline = CubicSpline(nodes, y, bc_type="periodic", axis=0)\n        basis = spline(xw).astype(np.float32)\n    except Exception:\n        basis = _manual_bspline_basis(xw, lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n        basis = np.asarray(basis, dtype=np.float32)\n        if basis.shape[1] >= n_knots:\n            basis = basis[:, :n_knots]\n        else:\n            pad = np.full((basis.shape[0], n_knots - basis.shape[1]), np.nan, dtype=np.float32)\n            basis = np.concatenate([basis, pad], axis=1)\n\n    out[np.flatnonzero(finite)] = basis\n    return out\n\n\ndef _add_basis_columns(store, basis_matrix, prefix):\n    for i in range(basis_matrix.shape[1]):\n        store[f"{prefix}_spline_b{i + 1:02d}"] = basis_matrix[:, i]\n\n\ndef _add_interaction_columns(store, left_matrix, right_matrix, name, max_terms=_INTERACTION_BASIS):\n    if left_matrix.size == 0 or right_matrix.size == 0:\n        return\n    left_terms = left_matrix[:, : min(max_terms, left_matrix.shape[1])]\n    right_terms = right_matrix[:, : min(max_terms, right_matrix.shape[1])]\n    for i in range(left_terms.shape[1]):\n        for j in range(right_terms.shape[1]):\n            store[f"{name}_b{i + 1:02d}_x{j + 1:02d}"] = left_terms[:, i] * right_terms[:, j]\n\n\ndef add_aide_smooth_spline_sed_interactions(raw, deps, aux):\n    _ = deps\n    aux_df = aux if isinstance(aux, pd.DataFrame) else pd.DataFrame()\n\n    alpha = _coerce_series(raw["alpha"])\n    delta = _coerce_series(raw["delta"])\n    u = _coerce_series(raw["u"])\n    g = _coerce_series(raw["g"])\n    r = _coerce_series(raw["r"])\n    i_band = _coerce_series(raw["i"])\n    z_band = _coerce_series(raw["z"])\n    redshift = _coerce_series(raw["redshift"])\n\n    alpha_aux = _coerce_series(aux_df["alpha"]) if not aux_df.empty and "alpha" in aux_df.columns else None\n    delta_aux = _coerce_series(aux_df["delta"]) if not aux_df.empty and "delta" in aux_df.columns else None\n    u_aux = _coerce_series(aux_df["u"]) if not aux_df.empty and "u" in aux_df.columns else None\n    g_aux = _coerce_series(aux_df["g"]) if not aux_df.empty and "g" in aux_df.columns else None\n    r_aux = _coerce_series(aux_df["r"]) if not aux_df.empty and "r" in aux_df.columns else None\n    i_aux = _coerce_series(aux_df["i"]) if not aux_df.empty and "i" in aux_df.columns else None\n    z_aux = _coerce_series(aux_df["z"]) if not aux_df.empty and "z" in aux_df.columns else None\n    redshift_aux = _coerce_series(aux_df["redshift"]) if not aux_df.empty and "redshift" in aux_df.columns else None\n\n    u_g, u_g_aux = _difference_series(raw, aux_df, "u", "g")\n    g_r, g_r_aux = _difference_series(raw, aux_df, "g", "r")\n    r_i, r_i_aux = _difference_series(raw, aux_df, "r", "i")\n    i_z, i_z_aux = _difference_series(raw, aux_df, "i", "z")\n    u_r, u_r_aux = _difference_series(raw, aux_df, "u", "r")\n    g_i, g_i_aux = _difference_series(raw, aux_df, "g", "i")\n    r_z, r_z_aux = _difference_series(raw, aux_df, "r", "z")\n    u_z, u_z_aux = _difference_series(raw, aux_df, "u", "z")\n\n    redshift_hi = _bounds_from_series(redshift, redshift_aux)[1]\n    if not np.isfinite(redshift_hi):\n        redshift_hi = float(redshift.max(skipna=True))\n    if not np.isfinite(redshift_hi):\n        redshift_hi = 0.0\n    clipped_redshift = redshift.clip(lower=0.0, upper=redshift_hi)\n    clipped_redshift_aux = redshift_aux.clip(lower=0.0, upper=redshift_hi) if redshift_aux is not None else None\n\n    feature_blocks = {}\n\n    alpha_bounds = _bounds_from_series(alpha, alpha_aux)\n    feature_blocks["alpha"] = _periodic_cubic_basis(alpha, alpha_bounds[0], alpha_bounds[1], _ALPHA_KNOTS)\n\n    delta_bounds = _bounds_from_series(delta, delta_aux)\n    feature_blocks["delta"] = _nonperiodic_cubic_basis(delta, delta_bounds[0], delta_bounds[1], _OTHER_KNOTS)\n\n    u_bounds = _bounds_from_series(u, u_aux)\n    feature_blocks["u"] = _nonperiodic_cubic_basis(u, u_bounds[0], u_bounds[1], _OTHER_KNOTS)\n\n    g_bounds = _bounds_from_series(g, g_aux)\n    feature_blocks["g"] = _nonperiodic_cubic_basis(g, g_bounds[0], g_bounds[1], _OTHER_KNOTS)\n\n    r_bounds = _bounds_from_series(r, r_aux)\n    feature_blocks["r"] = _nonperiodic_cubic_basis(r, r_bounds[0], r_bounds[1], _OTHER_KNOTS)\n\n    i_bounds = _bounds_from_series(i_band, i_aux)\n    feature_blocks["i"] = _nonperiodic_cubic_basis(i_band, i_bounds[0], i_bounds[1], _OTHER_KNOTS)\n\n    z_bounds = _bounds_from_series(z_band, z_aux)\n    feature_blocks["z"] = _nonperiodic_cubic_basis(z_band, z_bounds[0], z_bounds[1], _OTHER_KNOTS)\n\n    clipped_z_bounds = _bounds_from_series(clipped_redshift, clipped_redshift_aux)\n    feature_blocks["clipped_redshift"] = _nonperiodic_cubic_basis(\n        clipped_redshift, clipped_z_bounds[0], clipped_z_bounds[1], _OTHER_KNOTS\n    )\n\n    u_g_bounds = _bounds_from_series(u_g, u_g_aux)\n    feature_blocks["u_g"] = _nonperiodic_cubic_basis(u_g, u_g_bounds[0], u_g_bounds[1], _OTHER_KNOTS)\n\n    g_r_bounds = _bounds_from_series(g_r, g_r_aux)\n    feature_blocks["g_r"] = _nonperiodic_cubic_basis(g_r, g_r_bounds[0], g_r_bounds[1], _OTHER_KNOTS)\n\n    r_i_bounds = _bounds_from_series(r_i, r_i_aux)\n    feature_blocks["r_i"] = _nonperiodic_cubic_basis(r_i, r_i_bounds[0], r_i_bounds[1], _OTHER_KNOTS)\n\n    i_z_bounds = _bounds_from_series(i_z, i_z_aux)\n    feature_blocks["i_z"] = _nonperiodic_cubic_basis(i_z, i_z_bounds[0], i_z_bounds[1], _OTHER_KNOTS)\n\n    u_r_bounds = _bounds_from_series(u_r, u_r_aux)\n    feature_blocks["u_r"] = _nonperiodic_cubic_basis(u_r, u_r_bounds[0], u_r_bounds[1], _OTHER_KNOTS)\n\n    g_i_bounds = _bounds_from_series(g_i, g_i_aux)\n    feature_blocks["g_i"] = _nonperiodic_cubic_basis(g_i, g_i_bounds[0], g_i_bounds[1], _OTHER_KNOTS)\n\n    r_z_bounds = _bounds_from_series(r_z, r_z_aux)\n    feature_blocks["r_z"] = _nonperiodic_cubic_basis(r_z, r_z_bounds[0], r_z_bounds[1], _OTHER_KNOTS)\n\n    u_z_bounds = _bounds_from_series(u_z, u_z_aux)\n    feature_blocks["u_z"] = _nonperiodic_cubic_basis(u_z, u_z_bounds[0], u_z_bounds[1], _OTHER_KNOTS)\n\n    out = {}\n    for name, matrix in feature_blocks.items():\n        _add_basis_columns(out, matrix, name)\n\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["u_g"], "redshift_x_u_g")\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["g_r"], "redshift_x_g_r")\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["r_i"], "redshift_x_r_i")\n    _add_interaction_columns(out, feature_blocks["g_r"], feature_blocks["r_i"], "g_r_x_r_i")\n\n    return pd.DataFrame(out, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": _GROUP_NAME,\n        "fn": add_aide_smooth_spline_sed_interactions,\n        "depends_on": [],\n        "description": "Add cubic spline expansions for sky coordinates, photometry, clipped redshift, and color indices with compact interactions over redshift-color and adjacent color terms.",\n    }\n]'

HYPOTHESIS_000027_AUTOGLUON_002_PY_F66548D6EB_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_BLOCK_SIZES = (1000, 100000)\n_MOD_BASES = (2, 11, 97)\n\n\ndef add_aide_id_sequence_scan_context(raw, deps, aux):\n    n_rows = len(raw)\n    row_index = raw.index\n\n    if "id" in raw.columns:\n        id_values = pd.to_numeric(raw["id"], errors="coerce")\n        is_missing_id = id_values.isna().astype("bool")\n        sequence_values = id_values.astype(float).to_numpy(copy=True)\n\n        if is_missing_id.any():\n            fallback_row_order = np.arange(n_rows, dtype=float)\n            missing_positions = is_missing_id.to_numpy()\n            sequence_values[missing_positions] = fallback_row_order[missing_positions]\n    else:\n        is_missing_id = pd.Series(True, index=row_index, dtype="bool")\n        sequence_values = np.arange(n_rows, dtype=float)\n\n    sort_order = np.argsort(sequence_values, kind="mergesort")\n\n    rank_values = np.empty(n_rows, dtype=float)\n    rank_values[sort_order] = np.arange(1.0, float(n_rows) + 1.0)\n\n    rank_norm_values = (rank_values - 1.0) / max(n_rows - 1, 1)\n    floor_id = np.floor(sequence_values).astype(np.int64)\n\n    prev_gap_values = np.full(n_rows, np.nan, dtype=float)\n    next_gap_values = np.full(n_rows, np.nan, dtype=float)\n    if n_rows > 1:\n        sorted_sequence = sequence_values[sort_order]\n        prev_gap_values[sort_order[1:]] = np.diff(sorted_sequence)\n        next_gap_values[sort_order[:-1]] = np.diff(sorted_sequence)\n\n    block_size_1k, block_size_100k = _BLOCK_SIZES\n    mod_2, mod_11, mod_97 = _MOD_BASES\n\n    features = {\n        "aide_id_sequence_missing_id": is_missing_id.astype(bool),\n        "aide_id_sequence_rank": rank_values,\n        "aide_id_sequence_rank_norm": rank_norm_values,\n        "aide_id_sequence_block_1k": floor_id // block_size_1k,\n        "aide_id_sequence_block_100k": floor_id // block_size_100k,\n        "aide_id_sequence_mod_2": floor_id % mod_2,\n        "aide_id_sequence_mod_11": floor_id % mod_11,\n        "aide_id_sequence_mod_97": floor_id % mod_97,\n        "aide_id_sequence_is_even": (floor_id % 2) == 0,\n        "aide_id_sequence_log1p_id": np.log1p(np.clip(sequence_values, a_min=0.0, a_max=None)),\n        "aide_id_sequence_prev_gap": prev_gap_values,\n        "aide_id_sequence_next_gap": next_gap_values,\n    }\n\n    return pd.DataFrame(\n        {name: pd.Series(values, index=row_index) for name, values in features.items()},\n        index=row_index,\n    )\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_id_sequence_scan_context",\n        "fn": add_aide_id_sequence_scan_context,\n        "depends_on": [],\n        "description": "Extracts deterministic id-order context features including rank, normalized rank, coarse bins, parity, modulo residues, and neighborhood id gaps.",\n    }\n]'

HYPOTHESIS_000029_AUTOGLUON_001_PY_59BFE9DCC7_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_LYMAN_BANDS = ("u", "g", "r", "i", "z")\n_LYMAN_WAVELENGTHS = (3551.0, 4686.0, 6165.0, 7481.0, 8931.0)\n_LYMAN_BREAKS = (912.0, 1216.0)\n_EPS = 1e-12\n_MIN_DENOM = 1e-12\n\n\ndef _compute_single_break_features(rest_wavelength, flux_proxy, magnitudes, break_wave):\n    n_rows, n_bands = magnitudes.shape\n    rows = np.arange(n_rows, dtype=np.int64)\n\n    has_edge = rest_wavelength >= break_wave\n    available_mask = np.any(has_edge, axis=1)\n    break_idx = np.where(available_mask, has_edge.argmax(axis=1), n_bands).astype(np.int16)\n    edge_available = ((break_idx > 0) & (break_idx < n_bands)).astype(np.int8)\n\n    jump = np.zeros(n_rows, dtype=np.float64)\n    phase = np.zeros(n_rows, dtype=np.float64)\n    local = np.zeros(n_rows, dtype=np.float64)\n\n    active = edge_available.astype(bool)\n    if np.any(active):\n        active_rows = rows[active]\n        idx = break_idx[active]\n        left_idx = idx - 1\n\n        left_wave = rest_wavelength[active_rows, left_idx]\n        right_wave = rest_wavelength[active_rows, idx]\n        phase_active = (break_wave - left_wave) / (right_wave - left_wave)\n        phase[active_rows] = np.clip(phase_active, 0.0, 1.0)\n\n        left_mag = magnitudes[active_rows, left_idx]\n        right_mag = magnitudes[active_rows, idx]\n        local[active_rows] = left_mag - right_mag\n\n        active_flux = flux_proxy[active_rows]\n        cumsum_flux = np.cumsum(active_flux, axis=1)\n        low_sum = cumsum_flux[np.arange(active_flux.shape[0]), left_idx]\n        high_sum = cumsum_flux[:, -1] - low_sum\n        low_count = idx.astype(np.float64)\n        high_count = float(n_bands) - idx.astype(np.float64)\n\n        low_mean = low_sum / low_count\n        high_mean = high_sum / high_count\n        jump[active_rows] = np.log10((high_mean + _EPS) / (low_mean + _EPS))\n\n    return break_idx, edge_available, jump, phase, local\n\n\ndef add_redshifted_lyman_discontinuity(raw, deps, aux):\n    _ = (deps, aux)\n\n    required_columns = set(_LYMAN_BANDS) | {"redshift"}\n    missing_columns = required_columns - set(raw.columns)\n    if missing_columns:\n        raise KeyError(f"Missing required columns: {sorted(missing_columns)}")\n\n    base = "redshifted_lyman_discontinuity"\n\n    wavelengths = np.asarray(_LYMAN_WAVELENGTHS, dtype=np.float64)\n    z = pd.to_numeric(raw["redshift"], errors="coerce").to_numpy(dtype=np.float64)\n    denom = 1.0 + z\n    denom = np.where(np.isfinite(denom) & (denom > _MIN_DENOM), denom, np.nan)\n\n    mags = raw.loc[:, list(_LYMAN_BANDS)].to_numpy(dtype=np.float64)\n    flux = np.power(10.0, -0.4 * mags)\n    rest = wavelengths[None, :] / denom[:, None]\n\n    features = {}\n\n    for break_wave in _LYMAN_BREAKS:\n        break_idx, edge_available, jump, phase, local = _compute_single_break_features(rest, flux, mags, break_wave)\n        tag = str(int(break_wave))\n\n        features[f"{base}_jump_{tag}"] = pd.Series(jump, index=raw.index, dtype="float64")\n        features[f"{base}_phase_{tag}"] = pd.Series(phase, index=raw.index, dtype="float64")\n        features[f"{base}_local_{tag}"] = pd.Series(local, index=raw.index, dtype="float64")\n        features[f"{base}_break_band_{tag}"] = pd.Series(break_idx, index=raw.index, dtype="int16")\n        features[f"{base}_edge_available_{tag}"] = pd.Series(edge_available, index=raw.index, dtype="int8")\n        features[f"{base}_jump_x_break_band_{tag}"] = pd.Series(\n            jump * break_idx.astype(np.float64), index=raw.index, dtype="float64"\n        )\n        features[f"{base}_local_x_edge_{tag}"] = pd.Series(\n            local * edge_available.astype(np.float64), index=raw.index, dtype="float64"\n        )\n\n    return pd.DataFrame(features, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshifted_lyman_discontinuity",\n        "fn": add_redshifted_lyman_discontinuity,\n        "depends_on": [],\n        "description": "Compute redshifted Lyman-limit and Lyman-alpha dropout geometry features from ugriz flux proxies and rest-frame band boundaries.",\n    }\n]'

HYPOTHESIS_000056_AUTOGLUON_004_PY_6F54890526_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_CONTEXT_NSIDE = 32\n_REDSHIFT_STRATA = (-np.inf, 0.01, 0.1, 0.3, 0.5, 1.0, 2.0, np.inf)\n_N_STRATA = 7\n_MIN_CONTEXT_COUNT = 60\n_MAD_FLOOR = 1e-6\n_Z_MIN = -8.0\n_Z_MAX = 8.0\n_Q1_COEF = 1.582\n_Q2_COEF = 0.987\n\n\ndef _robust_mad(values):\n    arr = np.asarray(values, dtype=np.float64)\n    arr = arr[~pd.isna(arr)]\n    if arr.size == 0:\n        return np.nan\n    med = np.median(arr)\n    mad = np.median(np.abs(arr - med))\n    return float(mad)\n\n\ndef _fallback_context_and_neighbors(alpha, delta, nside):\n    ra = np.mod(np.asarray(alpha, dtype=np.float64), 360.0)\n    dec = np.asarray(delta, dtype=np.float64)\n\n    n_lon = 4 * nside\n    n_lat = 3 * nside\n\n    lat_edges = np.degrees(np.arcsin(np.linspace(-1.0, 1.0, n_lat + 1)))\n    lon_bin = np.floor((ra / 360.0) * n_lon).astype(np.int64)\n    lon_bin = np.mod(lon_bin, n_lon)\n    lat_bin = np.searchsorted(lat_edges, dec, side="right") - 1\n    lat_bin = np.clip(lat_bin, 0, n_lat - 1)\n\n    context = lat_bin * n_lon + lon_bin\n    context = np.clip(context, 0, n_lon * n_lat - 1).astype(np.int64)\n\n    unique_context = np.unique(context)\n    neighbor_map = {}\n    for ctx in unique_context:\n        lat_idx, lon_idx = divmod(int(ctx), n_lon)\n        neighbors = []\n        for dlat in (-1, 0, 1):\n            lat_n = lat_idx + dlat\n            if 0 <= lat_n < n_lat:\n                for dlon in (-1, 0, 1):\n                    lon_n = (lon_idx + dlon) % n_lon\n                    neighbors.append(lat_n * n_lon + lon_n)\n        neighbor_map[int(ctx)] = np.array(sorted(set(neighbors)), dtype=np.int64)\n    return context, neighbor_map\n\n\ndef _healpix_context_and_neighbors(alpha, delta, nside):\n    import healpy as hp\n\n    ra = np.mod(np.asarray(alpha, dtype=np.float64), 360.0)\n    dec = np.asarray(delta, dtype=np.float64)\n    theta = np.deg2rad(90.0 - np.clip(dec, -90.0, 90.0))\n    phi = np.deg2rad(ra)\n\n    context = hp.ang2pix(nside, theta, phi, nest=False).astype(np.int64)\n    unique_ctx = np.unique(context)\n\n    neighbor_map = {}\n    for ctx in unique_ctx:\n        ctx_i = int(ctx)\n        neigh = hp.get_all_neighbours(nside, ctx_i, nest=False)\n        neigh = np.asarray(neigh, dtype=np.int64)\n        neigh = neigh[neigh >= 0]\n        if neigh.size == 0:\n            neighbor_map[ctx_i] = np.array((ctx_i,), dtype=np.int64)\n        else:\n            neighbor_map[ctx_i] = np.unique(np.concatenate((np.array((ctx_i,), dtype=np.int64), neigh)))\n    return context, neighbor_map\n\n\ndef _context_and_neighbors(alpha, delta, nside):\n    try:\n        return _healpix_context_and_neighbors(alpha, delta, nside)\n    except Exception:\n        return _fallback_context_and_neighbors(alpha, delta, nside)\n\n\ndef add_local_reddening_free_locus_offsets(raw, deps, aux):\n    del deps\n    del aux\n\n    u = raw["u"].to_numpy(dtype=np.float64)\n    g = raw["g"].to_numpy(dtype=np.float64)\n    r = raw["r"].to_numpy(dtype=np.float64)\n    i = raw["i"].to_numpy(dtype=np.float64)\n    z = raw["z"].to_numpy(dtype=np.float64)\n    alpha = raw["alpha"].to_numpy(dtype=np.float64)\n    delta = raw["delta"].to_numpy(dtype=np.float64)\n    redshift = raw["redshift"].to_numpy(dtype=np.float64)\n\n    c_ug = u - g\n    c_gr = g - r\n    c_ri = r - i\n    c_iz = i - z\n    q1 = c_gr - _Q1_COEF * c_ri\n    q2 = c_ri - _Q2_COEF * c_iz\n\n    context, neighbor_map = _context_and_neighbors(alpha, delta, _CONTEXT_NSIDE)\n    context = context.astype(np.int64, copy=False)\n    stratum = np.asarray(\n        pd.cut(\n            redshift,\n            bins=_REDSHIFT_STRATA,\n            labels=False,\n            include_lowest=True,\n            right=False,\n        ),\n        dtype=np.int64,\n    )\n\n    base = pd.DataFrame(\n        {\n            "context": context,\n            "stratum": stratum,\n            "q1": q1,\n            "q2": q2,\n            "c_ug": c_ug,\n            "c_gr": c_gr,\n            "c_ri": c_ri,\n            "c_iz": c_iz,\n        },\n        index=raw.index,\n    )\n    feature_cols = ["q1", "q2", "c_ug", "c_gr", "c_ri", "c_iz"]\n\n    ctx_strat_counts = base.groupby(["context", "stratum"], sort=False).size()\n    ctx_all_counts = base.groupby("context", sort=False).size()\n\n    ctx_strat_count_dict = ctx_strat_counts.to_dict()\n    ctx_all_count_dict = ctx_all_counts.to_dict()\n\n    n = len(base)\n    n_ctx_strat = np.zeros(n, dtype=np.int64)\n    n_ctx_all = np.zeros(n, dtype=np.int64)\n    for row_idx, neigh_cells in enumerate(np.array([neighbor_map[int(c)] for c in context], dtype=object)):\n        s = int(stratum[row_idx])\n        total_strat = 0\n        total_all = 0\n        for neigh in neigh_cells:\n            neigh_i = int(neigh)\n            total_strat += int(ctx_strat_count_dict.get((neigh_i, s), 0))\n            total_all += int(ctx_all_count_dict.get(neigh_i, 0))\n        n_ctx_strat[row_idx] = total_strat\n        n_ctx_all[row_idx] = total_all\n\n    stratum_counts = np.bincount(stratum, minlength=_N_STRATA).astype(np.float64)\n    total_rows = float(n)\n\n    layer_ctx_strat = n_ctx_strat >= _MIN_CONTEXT_COUNT\n    layer_ctx_unstrat = (~layer_ctx_strat) & (n_ctx_all >= _MIN_CONTEXT_COUNT)\n    layer_global = (~layer_ctx_strat) & (~layer_ctx_unstrat)\n    layer_global_strat = layer_global & (stratum_counts[stratum] >= _MIN_CONTEXT_COUNT)\n    layer_global_full = layer_global & (~layer_global_strat)\n\n    strat_med = base.groupby(["context", "stratum"], sort=False)[feature_cols].median()\n    strat_mad = base.groupby(["context", "stratum"], sort=False)[feature_cols].agg(_robust_mad)\n    ctx_med = base.groupby("context", sort=False)[feature_cols].median()\n    ctx_mad = base.groupby("context", sort=False)[feature_cols].agg(_robust_mad)\n    global_strat_med = base.groupby("stratum", sort=False)[feature_cols].median()\n    global_strat_mad = base.groupby("stratum", sort=False)[feature_cols].agg(_robust_mad)\n    global_all_med = base[feature_cols].median()\n    global_all_mad = base[feature_cols].apply(_robust_mad)\n\n    idx = pd.MultiIndex.from_arrays(\n        [pd.Index(context, dtype=np.int64), pd.Index(stratum, dtype=np.int64)],\n        names=("context", "stratum"),\n    )\n\n    out = pd.DataFrame(index=raw.index)\n    for feat in feature_cols:\n        x = base[feat].to_numpy(dtype=np.float64)\n\n        med = np.full(n, float(global_all_med[feat]), dtype=np.float64)\n        mad = np.full(n, float(global_all_mad[feat]), dtype=np.float64)\n\n        med_strat = strat_med[feat].reindex(idx).to_numpy(dtype=np.float64)\n        mad_strat = strat_mad[feat].reindex(idx).to_numpy(dtype=np.float64)\n        med_ctx = ctx_med[feat].reindex(context).to_numpy(dtype=np.float64)\n        mad_ctx = ctx_mad[feat].reindex(context).to_numpy(dtype=np.float64)\n        med_global_strat = global_strat_med[feat].reindex(range(_N_STRATA)).to_numpy(dtype=np.float64)[stratum]\n        mad_global_strat = global_strat_mad[feat].reindex(range(_N_STRATA)).to_numpy(dtype=np.float64)[stratum]\n\n        miss = np.isnan(med_strat)\n        if miss.any():\n            med_strat[miss] = float(global_all_med[feat])\n            mad_strat[miss] = float(global_all_mad[feat])\n\n        miss = np.isnan(med_ctx)\n        if miss.any():\n            med_ctx[miss] = float(global_all_med[feat])\n            mad_ctx[miss] = float(global_all_mad[feat])\n\n        miss = np.isnan(med_global_strat)\n        if miss.any():\n            med_global_strat[miss] = float(global_all_med[feat])\n            mad_global_strat[miss] = float(global_all_mad[feat])\n\n        if layer_ctx_strat.any():\n            loc = np.flatnonzero(layer_ctx_strat)\n            med[loc] = med_strat[loc]\n            mad[loc] = mad_strat[loc]\n\n        if layer_ctx_unstrat.any():\n            loc = np.flatnonzero(layer_ctx_unstrat)\n            med[loc] = med_ctx[loc]\n            mad[loc] = mad_ctx[loc]\n\n        if layer_global_strat.any():\n            loc = np.flatnonzero(layer_global_strat)\n            med[loc] = med_global_strat[loc]\n            mad[loc] = mad_global_strat[loc]\n\n        mad = np.where(np.isfinite(mad) & (mad >= _MAD_FLOOR), mad, _MAD_FLOOR)\n        z = (x - med) / mad\n        out[f"z_{feat}"] = np.clip(z, _Z_MIN, _Z_MAX)\n\n    out["z_locus_deviation"] = np.sqrt(out["z_q1"] ** 2 + out["z_q2"] ** 2)\n\n    counts_df = ctx_strat_counts.reset_index(name="count")\n    logdens_ctx_strat_med = np.full(_N_STRATA, np.log1p(total_rows), dtype=np.float64)\n    logdens_ctx_strat_mad = np.full(_N_STRATA, _MAD_FLOOR, dtype=np.float64)\n    for s in range(_N_STRATA):\n        vals = counts_df.loc[counts_df["stratum"] == s, "count"].to_numpy(dtype=np.float64)\n        if vals.size:\n            lv = np.log1p(vals)\n            med = np.median(lv)\n            mad = np.median(np.abs(lv - med))\n            logdens_ctx_strat_med[s] = med\n            logdens_ctx_strat_mad[s] = mad if mad >= _MAD_FLOOR else _MAD_FLOOR\n        else:\n            logdens_ctx_strat_med[s] = np.log1p(stratum_counts[s])\n\n    log_ctx_counts = np.log1p(ctx_all_counts.to_numpy(dtype=np.float64))\n    logdens_ctx_med = np.median(log_ctx_counts)\n    logdens_ctx_mad = np.median(np.abs(log_ctx_counts - logdens_ctx_med))\n    if not np.isfinite(logdens_ctx_mad) or logdens_ctx_mad < _MAD_FLOOR:\n        logdens_ctx_mad = _MAD_FLOOR\n    logdens_ctx_med_by_strat = np.full(_N_STRATA, logdens_ctx_med, dtype=np.float64)\n    logdens_ctx_mad_by_strat = np.full(_N_STRATA, logdens_ctx_mad, dtype=np.float64)\n\n    logdens_global_strat_med = np.log1p(stratum_counts)\n    logdens_global_strat_mad = np.full(_N_STRATA, _MAD_FLOOR, dtype=np.float64)\n\n    logdens_global_all_med = np.log1p(total_rows)\n    logdens_global_all_mad = _MAD_FLOOR\n\n    log_nctx = np.zeros(n, dtype=np.float64)\n    log_med = np.zeros(n, dtype=np.float64)\n    log_mad = np.zeros(n, dtype=np.float64)\n\n    if layer_ctx_strat.any():\n        loc = np.flatnonzero(layer_ctx_strat)\n        log_nctx[loc] = n_ctx_strat[loc].astype(np.float64)\n        log_med[loc] = logdens_ctx_strat_med[stratum[loc]]\n        log_mad[loc] = logdens_ctx_strat_mad[stratum[loc]]\n\n    if layer_ctx_unstrat.any():\n        loc = np.flatnonzero(layer_ctx_unstrat)\n        log_nctx[loc] = n_ctx_all[loc].astype(np.float64)\n        log_med[loc] = logdens_ctx_med_by_strat[stratum[loc]]\n        log_mad[loc] = logdens_ctx_mad_by_strat[stratum[loc]]\n\n    if layer_global_strat.any():\n        loc = np.flatnonzero(layer_global_strat)\n        log_nctx[loc] = stratum_counts[stratum[loc]]\n        log_med[loc] = logdens_global_strat_med[stratum[loc]]\n        log_mad[loc] = logdens_global_strat_mad[stratum[loc]]\n\n    if layer_global_full.any():\n        loc = np.flatnonzero(layer_global_full)\n        log_nctx[loc] = total_rows\n        log_med[loc] = logdens_global_all_med\n        log_mad[loc] = logdens_global_all_mad\n\n    z_logdens = (np.log1p(log_nctx) - log_med) / np.maximum(log_mad, _MAD_FLOOR)\n    out["z_logdens"] = np.clip(z_logdens, _Z_MIN, _Z_MAX)\n\n    out["context_from_stratified"] = layer_ctx_strat\n    out["context_from_unstratified"] = layer_ctx_unstrat\n    out["context_from_global_fallback"] = layer_global\n\n    return out\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "local_reddening_free_locus_offsets",\n        "fn": add_local_reddening_free_locus_offsets,\n        "depends_on": [],\n        "description": "Builds local reddening-insensitive color residuals by comparing object colors to context-and-redshift robust loci and emits normalized offsets, density offsets, and context fallback indicators.",\n    }\n]'

